{
  "name": "Doce Palato - Comandas de Doces",
  "description": "Um sistema elegante e funcional para venda e gerenciamento de comandas de doces, com cardápio editável e um logotipo de brigadeiro animado."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Sweet {
  id: string;
  name: string;
  description: string;
  price: number;
  imageUrl: string;
}

export interface Section {
  id: string;
  title: string;
  items: Sweet[];
}

export interface CartItem extends Sweet {
  quantity: number;
}

import React, { useState, useEffect, useCallback } from 'react';
import { ShoppingBag, Settings, Plus, Send, Trash2, Edit2, ChevronDown, ChevronUp } from 'lucide-react';
import { Section, Sweet, CartItem } from './types';
import BrigadeiroLogo from './components/BrigadeiroLogo';
import SweetCard from './components/SweetCard';
import AdminPanel from './components/AdminPanel';
import CartSheet from './components/CartSheet';

const INITIAL_DATA: Section[] = [
  {
    id: '1',
    title: 'Brigadeiros Gourmet',
    items: [
      { id: 'b1', name: 'Brigadeiro Tradicional', description: 'Chocolate belga 54% com granulado macio.', price: 4.5, imageUrl: 'https://picsum.photos/seed/brig1/400/300' },
      { id: 'b2', name: 'Ninho com Nutella', description: 'Massa de leite ninho recheada com Nutella pura.', price: 5.5, imageUrl: 'https://picsum.photos/seed/brig2/400/300' }
    ]
  },
  {
    id: '2',
    title: 'Fatias de Bolo',
    items: [
      { id: 'f1', name: 'Cenoura com Chocolate', description: 'Fatia generosa com cobertura de brigadeiro quente.', price: 12.0, imageUrl: 'https://picsum.photos/seed/cake1/400/300' }
    ]
  }
];

const App: React.FC = () => {
  const [sections, setSections] = useState<Section[]>(() => {
    const saved = localStorage.getItem('doce-palato-sections');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isCartOpen, setIsCartOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('doce-palato-sections', JSON.stringify(sections));
  }, [sections]);

  const addToCart = (sweet: Sweet) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === sweet.id);
      if (existing) {
        return prev.map(item => item.id === sweet.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...sweet, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const clearCart = () => setCart([]);

  return (
    <div className="min-h-screen pb-20">
      {/* Header */}
      <header className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-pink-100 px-4 py-3 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <BrigadeiroLogo size={48} />
          <h1 className="font-logo text-2xl text-pink-600 mt-1">Doce Palato</h1>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => setIsAdminOpen(!isAdminOpen)}
            className="p-2 hover:bg-pink-50 rounded-full transition-colors text-pink-400"
            title="Gerenciar Cardápio"
          >
            <Settings size={24} />
          </button>
          <button 
            onClick={() => setIsCartOpen(true)}
            className="relative p-2 hover:bg-pink-50 rounded-full transition-colors text-pink-600"
          >
            <ShoppingBag size={24} />
            {cart.length > 0 && (
              <span className="absolute top-0 right-0 bg-pink-500 text-white text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full border-2 border-white">
                {cart.reduce((acc, item) => acc + item.quantity, 0)}
              </span>
            )}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-4xl mx-auto p-4 space-y-8">
        {isAdminOpen ? (
          <AdminPanel 
            sections={sections} 
            setSections={setSections} 
            onClose={() => setIsAdminOpen(false)} 
          />
        ) : (
          <div className="space-y-10">
            {sections.map(section => (
              <section key={section.id} className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                <h2 className="text-xl font-bold text-gray-800 mb-4 border-l-4 border-pink-500 pl-3">
                  {section.title}
                </h2>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {section.items.map(item => (
                    <SweetCard 
                      key={item.id} 
                      sweet={item} 
                      onAdd={() => addToCart(item)} 
                    />
                  ))}
                </div>
                {section.items.length === 0 && (
                  <p className="text-gray-400 italic text-sm">Nenhum doce nesta seção ainda.</p>
                )}
              </section>
            ))}
          </div>
        )}
      </main>

      {/* Cart Drawer */}
      <CartSheet 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        cart={cart}
        updateQuantity={updateQuantity}
        removeFromCart={removeFromCart}
        clearCart={clearCart}
      />

      {/* Floating Checkout Button (Mobile) */}
      {cart.length > 0 && !isCartOpen && (
        <button 
          onClick={() => setIsCartOpen(true)}
          className="fixed bottom-6 right-6 z-30 bg-pink-600 text-white shadow-xl shadow-pink-200 px-6 py-3 rounded-full flex items-center gap-2 font-bold hover:bg-pink-700 transition-all hover:scale-105 active:scale-95"
        >
          <ShoppingBag size={20} />
          <span>Ver Comanda (R$ {cart.reduce((acc, item) => acc + (item.price * item.quantity), 0).toFixed(2)})</span>
        </button>
      )}
    </div>
  );
};

export default App;

import React from 'react';

