  sweet: Sweet;
  onAdd: () => void;
}

const SweetCard: React.FC<Props> = ({ sweet, onAdd }) => {
  return (
    <div className="bg-white rounded-2xl p-3 flex gap-4 shadow-sm border border-pink-50 hover:shadow-md transition-shadow group">
      <div className="w-24 h-24 rounded-xl overflow-hidden flex-shrink-0 bg-pink-100">
