export default SweetCard;

import React, { useState } from 'react';
import { Plus, Trash2, Edit2, Check, X, Wand2 } from 'lucide-react';
import { Section, Sweet } from '../types';
import { GoogleGenAI, Type } from "@google/genai";

interface Props {
  sections: Section[];
  setSections: React.Dispatch<React.SetStateAction<Section[]>>;
  onClose: () => void;
}

const AdminPanel: React.FC<Props> = ({ sections, setSections, onClose }) => {
  const [isAddingSection, setIsAddingSection] = useState(false);
  const [newSectionTitle, setNewSectionTitle] = useState('');
  const [editingSweet, setEditingSweet] = useState<{ sectionId: string, sweet: Sweet | null }>({ sectionId: '', sweet: null });
  const [isGenerating, setIsGenerating] = useState(false);

  const addSection = () => {
    if (!newSectionTitle.trim()) return;
    const newSection: Section = {
      id: Date.now().toString(),
      title: newSectionTitle,
      items: []
    };
    setSections([...sections, newSection]);
    setNewSectionTitle('');
    setIsAddingSection(false);
  };

  const deleteSection = (id: string) => {
    if (confirm('Tem certeza que deseja remover esta seção e todos os seus doces?')) {
      setSections(sections.filter(s => s.id !== id));
    }
  };

  const startAddSweet = (sectionId: string) => {
    setEditingSweet({ 
      sectionId, 
      sweet: { id: Date.now().toString(), name: '', description: '', price: 0, imageUrl: `https://picsum.photos/seed/${Date.now()}/400/300` } 
    });
  };

  const saveSweet = () => {
    if (!editingSweet.sweet || !editingSweet.sweet.name) return;

    setSections(prev => prev.map(s => {
      if (s.id === editingSweet.sectionId) {
        const exists = s.items.find(item => item.id === editingSweet.sweet!.id);
        if (exists) {
          return { ...s, items: s.items.map(item => item.id === editingSweet.sweet!.id ? editingSweet.sweet! : item) };
        }
        return { ...s, items: [...s.items, editingSweet.sweet!] };
      }
      return s;
    }));
    setEditingSweet({ sectionId: '', sweet: null });
  };

  const deleteSweet = (sectionId: string, sweetId: string) => {
    setSections(prev => prev.map(s => {
      if (s.id === sectionId) {
        return { ...s, items: s.items.filter(item => item.id !== sweetId) };
      }
      return s;
    }));
  };

  const helpWithDescription = async () => {
    if (!editingSweet.sweet?.name) return;
    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Escreva uma descrição curta, irresistível e vendedora para um doce chamado "${editingSweet.sweet.name}". Use no máximo 15 palavras.`,
      });
      const desc = response.text || '';
      setEditingSweet(prev => prev.sweet ? ({
        ...prev,
        sweet: { ...prev.sweet, description: desc.trim().replace(/^"|"$/g, '') }
      }) : prev);
    } catch (e) {
      console.error(e);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-gray-800">Gerenciar Cardápio</h2>
        <button 
          onClick={onClose}
          className="text-gray-400 hover:text-gray-600"
        >
          <X size={24} />
        </button>
      </div>

      <div className="space-y-6">
        {sections.map(section => (
          <div key={section.id} className="bg-white rounded-2xl p-5 border border-gray-100 shadow-sm space-y-4">
            <div className="flex items-center justify-between border-b pb-3">
              <h3 className="font-bold text-lg text-pink-700">{section.title}</h3>
              <div className="flex gap-2">
                <button 
                  onClick={() => startAddSweet(section.id)}
                  className="flex items-center gap-1 text-sm bg-green-50 text-green-600 px-3 py-1 rounded-full hover:bg-green-100"
                >
                  <Plus size={16} /> Adicionar Doce
                </button>
                <button 
                  onClick={() => deleteSection(section.id)}
                  className="p-1.5 text-red-400 hover:text-red-600"
                >
                  <Trash2 size={18} />
                </button>
              </div>
            </div>

            <div className="grid grid-cols-1 gap-3">
              {section.items.map(item => (
                <div key={item.id} className="flex items-center justify-between p-2 rounded-xl border border-dashed border-gray-200">
                  <div className="flex items-center gap-3">
                    <img src={item.imageUrl} className="w-10 h-10 rounded-lg object-cover" alt="" />
                    <div>
                      <p className="font-medium text-sm text-gray-700">{item.name}</p>
                      <p className="text-xs text-gray-400">R$ {item.price.toFixed(2)}</p>
                    </div>
                  </div>
                  <div className="flex gap-1">
                    <button 
                      onClick={() => setEditingSweet({ sectionId: section.id, sweet: item })}
                      className="p-1.5 text-blue-400 hover:text-blue-600"
                    >
                      <Edit2 size={16} />
                    </button>
                    <button 
                      onClick={() => deleteSweet(section.id, item.id)}
                      className="p-1.5 text-red-300 hover:text-red-500"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}

        {isAddingSection ? (
          <div className="flex gap-2 bg-pink-50 p-4 rounded-2xl animate-in fade-in zoom-in-95">
            <input 
              autoFocus
              className="flex-grow bg-white border border-pink-200 rounded-xl px-4 py-2 outline-none focus:ring-2 ring-pink-300"
              placeholder="Nome da Seção (ex: Tortas)"
              value={newSectionTitle}
              onChange={e => setNewSectionTitle(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && addSection()}
            />
            <button 
              onClick={addSection}
              className="bg-pink-600 text-white p-2 rounded-xl"
            >
              <Check size={24} />
            </button>
            <button 
              onClick={() => setIsAddingSection(false)}
              className="bg-gray-200 text-gray-500 p-2 rounded-xl"
            >
              <X size={24} />
            </button>
          </div>
        ) : (
          <button 
            onClick={() => setIsAddingSection(true)}
            className="w-full py-4 border-2 border-dashed border-pink-200 text-pink-400 rounded-2xl flex items-center justify-center gap-2 hover:bg-pink-50 transition-colors"
          >
            <Plus size={20} /> Adicionar Nova Seção
          </button>
        )}
      </div>

      {/* Sweet Editor Modal Overlay */}
      {editingSweet.sweet && (
        <div className="fixed inset-0 z-50 bg-black/40 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-3xl p-6 shadow-2xl animate-in slide-in-from-bottom-8">
            <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
              <Edit2 size={20} className="text-pink-600" />
              Editar Doce
            </h3>
            <div className="space-y-4">
              <div>
                <label className="text-xs font-bold text-gray-400 uppercase ml-1">Nome</label>
                <input 
                  className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 mt-1 outline-none focus:ring-2 ring-pink-100"
                  value={editingSweet.sweet.name}
                  onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, name: e.target.value } })}
                  placeholder="Nome do doce"
                />
              </div>
              <div>
                <label className="text-xs font-bold text-gray-400 uppercase ml-1 flex justify-between">
                  Descrição
                  <button 
                    onClick={helpWithDescription}
                    disabled={isGenerating || !editingSweet.sweet.name}
                    className="text-pink-500 hover:text-pink-700 flex items-center gap-1 normal-case font-medium disabled:opacity-50"
                  >
                    <Wand2 size={12} /> {isGenerating ? 'Gerando...' : 'Pedir ajuda à IA'}
                  </button>
                </label>
                <textarea 
                  className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 mt-1 outline-none focus:ring-2 ring-pink-100 min-h-[80px]"
                  value={editingSweet.sweet.description}
                  onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, description: e.target.value } })}
                  placeholder="Dê uma descrição apetitosa..."
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-xs font-bold text-gray-400 uppercase ml-1">Preço (R$)</label>
                  <input 
                    type="number"
                    className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 mt-1 outline-none focus:ring-2 ring-pink-100"
                    value={editingSweet.sweet.price || ''}
                    onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, price: parseFloat(e.target.value) || 0 } })}
                    placeholder="0.00"
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-gray-400 uppercase ml-1">Imagem URL</label>
                  <input 
                    className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 mt-1 outline-none focus:ring-2 ring-pink-100"
                    value={editingSweet.sweet.imageUrl}
                    onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, imageUrl: e.target.value } })}
                    placeholder="https://..."
                  />
                </div>
              </div>
            </div>
            <div className="flex gap-3 mt-8">
              <button 
                onClick={() => setEditingSweet({ sectionId: '', sweet: null })}
                className="flex-1 bg-gray-100 text-gray-600 font-bold py-3 rounded-xl hover:bg-gray-200 transition-colors"
              >
                Cancelar
              </button>
              <button 
                onClick={saveSweet}
                className="flex-1 bg-pink-600 text-white font-bold py-3 rounded-xl hover:bg-pink-700 transition-colors shadow-lg shadow-pink-100"
              >
                Salvar Doce
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React from 'react';
import { X, Minus, Plus, Trash2, Send, AlertCircle } from 'lucide-react';
import { CartItem } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  updateQuantity: (id: string, delta: number) => void;
  removeFromCart: (id: string) => void;
  clearCart: () => void;
}

const CartSheet: React.FC<Props> = ({ isOpen, onClose, cart, updateQuantity, removeFromCart, clearCart }) => {
  if (!isOpen) return null;

  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const sendToWhatsApp = () => {
    const message = `*Comanda Doce Palato*\n\n` + 
      cart.map(item => `• ${item.quantity}x ${item.name} - R$ ${(item.price * item.quantity).toFixed(2)}`).join('\n') +
      `\n\n*Total: R$ ${total.toFixed(2)}*`;

    const encoded = encodeURIComponent(message);
    window.open(`https://wa.me/?text=${encoded}`, '_blank');
    clearCart();
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex justify-end">
      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-black/30 backdrop-blur-sm animate-in fade-in"
        onClick={onClose}
      />

      {/* Content */}
      <div className="relative w-full max-w-md bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
        <div className="p-6 border-b flex items-center justify-between">
          <div className="flex items-center gap-2">
            <h2 className="text-2xl font-bold text-gray-800">Sua Comanda</h2>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-full text-gray-400">
            <X size={24} />
          </button>
        </div>

        <div className="flex-grow overflow-y-auto p-6 space-y-6">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-4">
              <div className="w-20 h-20 bg-pink-50 rounded-full flex items-center justify-center text-pink-300">
                <Trash2 size={40} />
              </div>
              <div>
                <p className="text-lg font-bold text-gray-700">Comanda vazia</p>
                <p className="text-gray-400">Adicione alguns doces para começar!</p>
              </div>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.id} className="flex gap-4 items-start group">
                <div className="w-16 h-16 rounded-lg overflow-hidden bg-gray-100 flex-shrink-0">
                  <img src={item.imageUrl} alt={item.name} className="w-full h-full object-cover" />
                </div>
                <div className="flex-grow">
                  <div className="flex justify-between">
                    <h4 className="font-bold text-gray-800 text-sm">{item.name}</h4>
                    <button 
                      onClick={() => removeFromCart(item.id)}
                      className="text-gray-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                  <p className="text-xs text-pink-600 font-bold mb-2">R$ {item.price.toFixed(2)}</p>
                  <div className="flex items-center gap-3">
                    <div className="flex items-center bg-gray-50 rounded-lg p-1 border border-gray-100">
                      <button 
                        onClick={() => updateQuantity(item.id, -1)}
                        className="p-1 text-gray-400 hover:text-pink-600"
                      >
                        <Minus size={14} />
                      </button>
                      <span className="w-8 text-center text-xs font-bold text-gray-700">{item.quantity}</span>
                      <button 
                        onClick={() => updateQuantity(item.id, 1)}
                        className="p-1 text-gray-400 hover:text-pink-600"
                      >
                        <Plus size={14} />
                      </button>
                    </div>
                    <span className="text-xs font-bold text-gray-500">
                      Subtotal: R$ {(item.price * item.quantity).toFixed(2)}
                    </span>
                  </div>
                </div>
