  const [isAddingSection, setIsAddingSection] = useState(false);
  const [newSectionTitle, setNewSectionTitle] = useState('');
  const [editingSweet, setEditingSweet] = useState<{ sectionId: string, sweet: Sweet | null }>({ sectionId: '', sweet: null });
  const [isGenerating, setIsGenerating] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const addSection = () => {
    if (!newSectionTitle.trim()) return;
    const newSection: Section = {
      id: Date.now().toString(),
      title: newSectionTitle,
      items: []
    };
    setSections([...sections, newSection]);
    setNewSectionTitle('');
    setIsAddingSection(false);
  };

  const deleteSection = (id: string) => {
    if (confirm('Tem certeza que deseja remover esta seção e todos os seus doces?')) {
      setSections(sections.filter(s => s.id !== id));
    }
  };

  const startAddSweet = (sectionId: string) => {
    setEditingSweet({ 
      sectionId, 
      sweet: { id: Date.now().toString(), name: '', description: '', price: 0, imageUrl: 'https://images.unsplash.com/photo-1570476922354-81227cdbb76c?q=80&w=400&h=300&auto=format&fit=crop' } 
    });
  };

  const saveSweet = () => {
    if (!editingSweet.sweet || !editingSweet.sweet.name) return;

    setSections(prev => prev.map(s => {
      if (s.id === editingSweet.sectionId) {
        const exists = s.items.find(item => item.id === editingSweet.sweet!.id);
        if (exists) {
          return { ...s, items: s.items.map(item => item.id === editingSweet.sweet!.id ? editingSweet.sweet! : item) };
        }
        return { ...s, items: [...s.items, editingSweet.sweet!] };
      }
      return s;
    }));
    setEditingSweet({ sectionId: '', sweet: null });
  };

  const deleteSweet = (sectionId: string, sweetId: string) => {
    setSections(prev => prev.map(s => {
      if (s.id === sectionId) {
        return { ...s, items: s.items.filter(item => item.id !== sweetId) };
      }
      return s;
    }));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editingSweet.sweet) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditingSweet({
          ...editingSweet,
          sweet: { ...editingSweet.sweet!, imageUrl: reader.result as string }
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const helpWithDescription = async () => {
    if (!editingSweet.sweet?.name) return;
    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Escreva uma descrição curta, irresistível e vendedora para um doce chamado "${editingSweet.sweet.name}". Use no máximo 15 palavras.`,
      });
      const desc = response.text || '';
      setEditingSweet(prev => prev.sweet ? ({
        ...prev,
        sweet: { ...prev.sweet, description: desc.trim().replace(/^"|"$/g, '') }
      }) : prev);
    } catch (e) {
      console.error(e);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-gray-800">Gerenciar Cardápio</h2>
        <button 
          onClick={onClose}
          className="text-gray-400 hover:text-gray-600"
        >
          <X size={24} />
        </button>
      </div>

      <div className="space-y-6">
        {sections.map(section => (
          <div key={section.id} className="bg-white rounded-2xl p-5 border border-gray-100 shadow-sm space-y-4">
            <div className="flex items-center justify-between border-b pb-3">
              <h3 className="font-bold text-lg text-pink-700">{section.title}</h3>
              <div className="flex gap-2">
                <button 
                  onClick={() => startAddSweet(section.id)}
                  className="flex items-center gap-1 text-sm bg-green-50 text-green-600 px-3 py-1 rounded-full hover:bg-green-100"
                >
                  <Plus size={16} /> Adicionar Doce
                </button>
                <button 
                  onClick={() => deleteSection(section.id)}
                  className="p-1.5 text-red-400 hover:text-red-600"
                >
                  <Trash2 size={18} />
                </button>
              </div>
            </div>

            <div className="grid grid-cols-1 gap-3">
              {section.items.map(item => (
                <div key={item.id} className="flex items-center justify-between p-2 rounded-xl border border-dashed border-gray-200">
                  <div className="flex items-center gap-3">
                    <img src={item.imageUrl} className="w-10 h-10 rounded-lg object-cover" alt="" />
                    <div>
                      <p className="font-medium text-sm text-gray-700">{item.name}</p>
                      <p className="text-xs text-gray-400">R$ {item.price.toFixed(2)}</p>
                    </div>
                  </div>
                  <div className="flex gap-1">
                    <button 
                      onClick={() => setEditingSweet({ sectionId: section.id, sweet: item })}
                      className="p-1.5 text-blue-400 hover:text-blue-600"
                    >
                      <Edit2 size={16} />
                    </button>
                    <button 
                      onClick={() => deleteSweet(section.id, item.id)}
                      className="p-1.5 text-red-300 hover:text-red-500"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}

        {isAddingSection ? (
          <div className="flex gap-2 bg-pink-50 p-4 rounded-2xl animate-in fade-in zoom-in-95">
            <input 
              autoFocus
              className="flex-grow bg-white border border-pink-200 rounded-xl px-4 py-2 outline-none focus:ring-2 ring-pink-300 text-gray-800"
              placeholder="Nome da Seção (ex: Tortas)"
              value={newSectionTitle}
              onChange={e => setNewSectionTitle(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && addSection()}
            />
            <button 
              onClick={addSection}
              className="bg-pink-600 text-white p-2 rounded-xl"
            >
              <Check size={24} />
            </button>
            <button 
              onClick={() => setIsAddingSection(false)}
              className="bg-gray-200 text-gray-500 p-2 rounded-xl"
            >
              <X size={24} />
            </button>
          </div>
        ) : (
          <button 
            onClick={() => setIsAddingSection(true)}
            className="w-full py-4 border-2 border-dashed border-pink-200 text-pink-400 rounded-2xl flex items-center justify-center gap-2 hover:bg-pink-50 transition-colors"
          >
            <Plus size={20} /> Adicionar Nova Seção
          </button>
        )}
      </div>

      {/* Sweet Editor Modal Overlay */}
      {editingSweet.sweet && (
        <div className="fixed inset-0 z-50 bg-black/40 backdrop-blur-sm flex items-center justify-center p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-md rounded-3xl p-6 shadow-2xl animate-in slide-in-from-bottom-8 my-auto">
            <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
              <Edit2 size={20} className="text-pink-600" />
              Editar Doce
            </h3>
            <div className="space-y-4">
              {/* Image Preview and Upload */}
              <div className="flex flex-col items-center gap-3">
                <div className="w-32 h-32 rounded-2xl overflow-hidden bg-gray-100 border-2 border-pink-100 relative group">
                  <img src={editingSweet.sweet.imageUrl} className="w-full h-full object-cover" alt="Preview" />
                  <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="absolute inset-0 bg-black/40 text-white opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity"
                  >
                    <Upload size={24} />
                  </button>
                </div>
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="text-xs font-bold text-pink-600 hover:text-pink-700 flex items-center gap-1 uppercase tracking-wider"
                >
                  <Upload size={14} /> Alterar Foto
                </button>
                <input 
                  type="file"
                  ref={fileInputRef}
                  className="hidden"
                  accept="image/*"
                  onChange={handleFileChange}
                />
              </div>

              <div>
                <label className="text-xs font-bold text-gray-400 uppercase ml-1 block">Nome</label>
                <input 
                  className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 mt-1 outline-none focus:ring-2 ring-pink-100 text-gray-800"
                  value={editingSweet.sweet.name}
                  onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, name: e.target.value } })}
                  placeholder="Nome do doce"
                />
              </div>

              <div>
                <label className="text-xs font-bold text-gray-400 uppercase ml-1 flex justify-between">
                  Descrição
                  <button 
                    onClick={helpWithDescription}
                    disabled={isGenerating || !editingSweet.sweet.name}
                    className="text-pink-500 hover:text-pink-700 flex items-center gap-1 normal-case font-medium disabled:opacity-50"
                  >
                    <Wand2 size={12} /> {isGenerating ? 'Gerando...' : 'Pedir ajuda à IA'}
                  </button>
                </label>
                <textarea 
                  className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 mt-1 outline-none focus:ring-2 ring-pink-100 min-h-[80px] text-gray-800"
                  value={editingSweet.sweet.description}
                  onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, description: e.target.value } })}
                  placeholder="Dê uma descrição apetitosa..."
                />
              </div>

              <div className="grid grid-cols-1 gap-4">
                <div>
                  <label className="text-xs font-bold text-gray-400 uppercase ml-1">Preço (R$)</label>
                  <input 
                    type="number"
                    step="0.01"
                    className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 mt-1 outline-none focus:ring-2 ring-pink-100 text-gray-800"
                    value={editingSweet.sweet.price || ''}
                    onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, price: parseFloat(e.target.value) || 0 } })}
                    placeholder="0.00"
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-gray-400 uppercase ml-1 block mb-1">Ou Cole uma URL de Imagem</label>
                  <div className="relative">
                    <ImageIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                    <input 
                      className="w-full bg-gray-50 border border-gray-200 rounded-xl pl-10 pr-4 py-2 outline-none focus:ring-2 ring-pink-100 text-gray-800 text-sm"
                      value={editingSweet.sweet.imageUrl.startsWith('data:') ? '' : editingSweet.sweet.imageUrl}
                      onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, imageUrl: e.target.value } })}
                      placeholder="https://..."
                    />
                  </div>
                </div>
              </div>
            </div>
            <div className="flex gap-3 mt-8">
              <button 
                onClick={() => setEditingSweet({ sectionId: '', sweet: null })}
                className="flex-1 bg-gray-100 text-gray-600 font-bold py-3 rounded-xl hover:bg-gray-200 transition-colors"
              >
                Cancelar
              </button>
              <button 
                onClick={saveSweet}
                className="flex-1 bg-pink-600 text-white font-bold py-3 rounded-xl hover:bg-pink-700 transition-colors shadow-lg shadow-pink-100"
              >
                Salvar Doce
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState } from 'react';
import { X, Minus, Plus, Trash2, Send, User, MessageSquare } from 'lucide-react';
import { CartItem } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  updateQuantity: (id: string, delta: number) => void;
  removeFromCart: (id: string) => void;
  clearCart: () => void;
}

const CartSheet: React.FC<Props> = ({ isOpen, onClose, cart, updateQuantity, removeFromCart, clearCart }) => {
  const [customerName, setCustomerName] = useState('');
  const [notes, setNotes] = useState('');

  if (!isOpen) return null;

  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const sendToWhatsApp = () => {
    if (!customerName.trim()) {
      alert('Por favor, informe seu nome para a comanda.');
      return;
    }

    const header = `*🍰 COMANDA - DOCE PALATO* 🍰\n`;
    const customer = `\n👤 *Cliente:* ${customerName}\n`;
    const items = cart.map(item => `• ${item.quantity}x ${item.name} (_R$ ${item.price.toFixed(2)} uni._)`).join('\n');
    const footer = `\n\n💰 *Total: R$ ${total.toFixed(2)}*`;
    const obs = notes.trim() ? `\n\n📝 *Observações:* ${notes}` : '';

    const message = `${header}${customer}\n*Itens:*\n${items}${obs}${footer}`;

    const encoded = encodeURIComponent(message);
    window.open(`https://wa.me/?text=${encoded}`, '_blank');
    // Opcional: não limpar o carrinho imediatamente caso o envio falhe, 
    // mas aqui limpamos para simular a conclusão do pedido
    clearCart();
    setCustomerName('');
    setNotes('');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex justify-end">
      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-black/40 backdrop-blur-sm animate-in fade-in"
        onClick={onClose}
      />

      {/* Content */}
      <div className="relative w-full max-w-md bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
        <div className="p-6 border-b flex items-center justify-between bg-pink-50">
          <div>
            <h2 className="text-2xl font-bold text-pink-800">Sua Comanda</h2>
            <p className="text-xs text-pink-600 font-medium uppercase tracking-wider">Doce Palato</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white rounded-full text-pink-400 transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="flex-grow overflow-y-auto p-6 space-y-6">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-4">
              <div className="w-20 h-20 bg-pink-50 rounded-full flex items-center justify-center text-pink-200">
                <Trash2 size={40} />
              </div>
              <div>
                <p className="text-lg font-bold text-gray-700">Sacola vazia</p>
                <p className="text-gray-400">Escolha seus doces favoritos no cardápio!</p>
              </div>
            </div>
          ) : (
            <>
              <div className="space-y-4">
                {cart.map(item => (
                  <div key={item.id} className="flex gap-4 items-center p-3 rounded-2xl bg-gray-50 border border-gray-100 group">
                    <div className="w-14 h-14 rounded-xl overflow-hidden bg-white flex-shrink-0 border border-pink-50">
                      <img src={item.imageUrl} alt={item.name} className="w-full h-full object-cover" />
                    </div>
                    <div className="flex-grow">
                      <div className="flex justify-between items-start">
                        <h4 className="font-bold text-gray-800 text-sm leading-tight">{item.name}</h4>
                        <button 
                          onClick={() => removeFromCart(item.id)}
                          className="text-gray-300 hover:text-red-500 transition-colors ml-2"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                      <div className="flex items-center justify-between mt-1">
                        <span className="text-xs font-bold text-pink-600">R$ {(item.price * item.quantity).toFixed(2)}</span>
                        <div className="flex items-center bg-white rounded-lg p-0.5 border border-pink-100 shadow-sm">
                          <button 
                            onClick={() => updateQuantity(item.id, -1)}
                            className="p-1 text-pink-400 hover:bg-pink-50 rounded"
                          >
                            <Minus size={12} />
                          </button>
                          <span className="w-6 text-center text-xs font-bold text-gray-700">{item.quantity}</span>
                          <button 
                            onClick={() => updateQuantity(item.id, 1)}
                            className="p-1 text-pink-400 hover:bg-pink-50 rounded"
                          >
                            <Plus size={12} />
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>

              <div className="space-y-4 pt-4 border-t border-dashed border-gray-200">
                <div>
                  <label className="text-xs font-bold text-gray-400 uppercase ml-1 flex items-center gap-1 mb-1">
                    <User size={12} /> Seu Nome
                  </label>
                  <input 
                    className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 outline-none focus:ring-2 ring-pink-100 text-gray-800 transition-all"
                    placeholder="Como podemos te chamar?"
                    value={customerName}
                    onChange={e => setCustomerName(e.target.value)}
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-gray-400 uppercase ml-1 flex items-center gap-1 mb-1">
                    <MessageSquare size={12} /> Observações
                  </label>
                  <textarea 
                    className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 outline-none focus:ring-2 ring-pink-100 text-gray-800 transition-all min-h-[60px]"
                    placeholder="Alguma alergia ou detalhe especial?"
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                  />
                </div>
              </div>
            </>
          )}
        </div>

        {cart.length > 0 && (
          <div className="p-6 border-t bg-white shadow-[0_-10px_20px_-5px_rgba(0,0,0,0.05)] space-y-4">
            <div className="flex justify-between items-end">
              <div>
                <p className="text-xs text-gray-400 font-bold uppercase">Valor Total</p>
                <p className="text-3xl font-bold text-pink-600">R$ {total.toFixed(2)}</p>
              </div>
              <div className="text-right">
                <p className="text-[10px] text-gray-400 uppercase font-bold">{cart.length} itens na sacola</p>
              </div>
            </div>
            <button 
              onClick={sendToWhatsApp}
              className="w-full bg-green-600 text-white font-bold py-4 rounded-2xl flex items-center justify-center gap-3 hover:bg-green-700 transition-all shadow-lg shadow-green-100 active:scale-[0.98]"
            >
              <Send size={20} />
              Enviar Comanda via WhatsApp
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default CartSheet;

import React, { useState, useEffect } from 'react';
import { ShoppingBag, Settings, LogOut } from 'lucide-react';
import { Section, Sweet, CartItem } from './types';
import BrigadeiroLogo from './components/BrigadeiroLogo';
import SweetCard from './components/SweetCard';
import AdminPanel from './components/AdminPanel';
import CartSheet from './components/CartSheet';
import LoginForm from './components/LoginForm';

const INITIAL_DATA: Section[] = [
  {
    id: '1',
    title: 'Brigadeiros Gourmet',
    items: [
      { id: 'b1', name: 'Brigadeiro Tradicional', description: 'Chocolate belga 54% com granulado macio.', price: 4.5, imageUrl: 'https://images.unsplash.com/photo-1599599810769-bcde5a160d32?auto=format&fit=crop&q=80&w=400' },
      { id: 'b2', name: 'Ninho com Nutella', description: 'Massa de leite ninho recheada com Nutella pura.', price: 5.5, imageUrl: 'https://images.unsplash.com/photo-1548365328-8c6db3220e4c?auto=format&fit=crop&q=80&w=400' }
    ]
  },
  {
    id: '2',
    title: 'Fatias de Bolo',
    items: [
      { id: 'f1', name: 'Cenoura com Chocolate', description: 'Fatia generosa com cobertura de brigadeiro quente.', price: 12.0, imageUrl: 'https://images.unsplash.com/photo-1578985545062-69928b1d9587?auto=format&fit=crop&q=80&w=400' }
    ]
  }
];

const App: React.FC = () => {
  const [sections, setSections] = useState<Section[]>(() => {
    const saved = localStorage.getItem('doce-palato-sections');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isCartOpen, setIsCartOpen] = useState(false);

  // Efeito de salvamento automático: qualquer mudança em 'sections' salva no localStorage instantaneamente
  useEffect(() => {
    localStorage.setItem('doce-palato-sections', JSON.stringify(sections));
  }, [sections]);

  const addToCart = (sweet: Sweet) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === sweet.id);
      if (existing) {
        return prev.map(item => item.id === sweet.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...sweet, quantity: 1 }];
    });
    // Feedback visual opcional: abrir a sacola ou mostrar um alerta
    // setIsCartOpen(true); 
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const clearCart = () => setCart([]);

  const handleToggleAdmin = () => {
    setIsAdminOpen(!isAdminOpen);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setIsAdminOpen(false);
  };

  return (
    <div className="min-h-screen pb-20 selection:bg-pink-100 selection:text-pink-600">
      {/* Header */}
      <header className="sticky top-0 z-40 bg-white/90 backdrop-blur-lg border-b border-pink-50 px-4 py-3 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => setIsAdminOpen(false)}>
          <BrigadeiroLogo size={42} />
          <div>
            <h1 className="font-logo text-xl text-pink-600 leading-none">Doce Palato</h1>
            <p className="text-[10px] text-pink-400 font-bold uppercase tracking-tighter">O sabor da felicidade</p>
          </div>
        </div>

        <div className="flex items-center gap-2">
          {isLoggedIn && isAdminOpen && (
             <button 
              onClick={handleLogout}
              className="p-2 hover:bg-red-50 rounded-full transition-colors text-red-400"
              title="Sair"
           >
             <LogOut size={22} />
           </button>
          )}
          <button 
            onClick={handleToggleAdmin}
            className={`p-2 rounded-full transition-all ${isAdminOpen ? 'bg-pink-600 text-white' : 'hover:bg-pink-50 text-pink-400'}`}
            title="Gerenciar Cardápio"
          >
            <Settings size={22} />
          </button>
          <button 
            onClick={() => setIsCartOpen(true)}
            className="relative p-2 hover:bg-pink-50 rounded-full transition-all text-pink-600"
          >
            <ShoppingBag size={22} />
            {cart.length > 0 && (
              <span className="absolute -top-1 -right-1 bg-pink-500 text-white text-[9px] font-black w-5 h-5 flex items-center justify-center rounded-full border-2 border-white animate-in zoom-in">
                {cart.reduce((acc, item) => acc + item.quantity, 0)}
              </span>
            )}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-4xl mx-auto p-4 md:p-6 space-y-8">
        {isAdminOpen ? (
          isLoggedIn ? (
            <AdminPanel 
              sections={sections} 
              setSections={setSections} 
              onClose={() => setIsAdminOpen(false)} 
            />
          ) : (
            <LoginForm onLoginSuccess={() => setIsLoggedIn(true)} />
          )
        ) : (
