import { GoogleGenAI, Type } from "@google/genai";

interface Props {
  sections: Section[];
  setSections: React.Dispatch<React.SetStateAction<Section[]>>;
  onClose: () => void;
}

const AdminPanel: React.FC<Props> = ({ sections, setSections, onClose }) => {
  const [isAddingSection, setIsAddingSection] = useState(false);
  const [newSectionTitle, setNewSectionTitle] = useState('');
  const [editingSweet, setEditingSweet] = useState<{ sectionId: string, sweet: Sweet | null }>({ sectionId: '', sweet: null });
  const [isGenerating, setIsGenerating] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const addSection = () => {
    if (!newSectionTitle.trim()) return;
    const newSection: Section = {
      id: Date.now().toString(),
      title: newSectionTitle,
      items: []
    };
    setSections([...sections, newSection]);
    setNewSectionTitle('');
    setIsAddingSection(false);
  };

  const deleteSection = (id: string) => {
    if (confirm('Tem certeza que deseja remover esta seção e todos os seus doces?')) {
      setSections(sections.filter(s => s.id !== id));
    }
  };

  const startAddSweet = (sectionId: string) => {
    setEditingSweet({ 
      sectionId, 
      sweet: { id: Date.now().toString(), name: '', description: '', price: 0, imageUrl: 'https://images.unsplash.com/photo-1570476922354-81227cdbb76c?q=80&w=400&h=300&auto=format&fit=crop' } 
    });
  };

  const saveSweet = () => {
    if (!editingSweet.sweet || !editingSweet.sweet.name) return;

    setSections(prev => prev.map(s => {
      if (s.id === editingSweet.sectionId) {
        const exists = s.items.find(item => item.id === editingSweet.sweet!.id);
        if (exists) {
          return { ...s, items: s.items.map(item => item.id === editingSweet.sweet!.id ? editingSweet.sweet! : item) };
        }
        return { ...s, items: [...s.items, editingSweet.sweet!] };
      }
      return s;
    }));
    setEditingSweet({ sectionId: '', sweet: null });
  };

  const deleteSweet = (sectionId: string, sweetId: string) => {
    setSections(prev => prev.map(s => {
      if (s.id === sectionId) {
        return { ...s, items: s.items.filter(item => item.id !== sweetId) };
      }
      return s;
    }));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editingSweet.sweet) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditingSweet({
          ...editingSweet,
          sweet: { ...editingSweet.sweet!, imageUrl: reader.result as string }
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const helpWithDescription = async () => {
    if (!editingSweet.sweet?.name) return;
    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Escreva uma descrição curta, irresistível e vendedora para um doce chamado "${editingSweet.sweet.name}". Use no máximo 15 palavras.`,
      });
      const desc = response.text || '';
      setEditingSweet(prev => prev.sweet ? ({
        ...prev,
        sweet: { ...prev.sweet, description: desc.trim().replace(/^"|"$/g, '') }
      }) : prev);
    } catch (e) {
      console.error(e);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-stone-800">Gerenciar Cardápio</h2>
        <button onClick={onClose} className="text-stone-400 hover:text-stone-600">
          <X size={24} />
        </button>
      </div>

      <div className="space-y-6">
        {sections.map(section => (
          <div key={section.id} className="bg-white rounded-2xl p-5 border border-stone-100 shadow-sm space-y-4">
            <div className="flex items-center justify-between border-b pb-3">
              <h3 className="font-bold text-lg text-orange-800">{section.title}</h3>
              <div className="flex gap-2">
                <button 
                  onClick={() => startAddSweet(section.id)}
                  className="flex items-center gap-1 text-sm bg-orange-50 text-orange-800 px-3 py-1 rounded-full hover:bg-orange-100"
                >
                  <Plus size={16} /> Adicionar Doce
                </button>
                <button onClick={() => deleteSection(section.id)} className="p-1.5 text-stone-300 hover:text-orange-800">
                  <Trash2 size={18} />
                </button>
              </div>
            </div>

            <div className="grid grid-cols-1 gap-3">
              {section.items.map(item => (
                <div key={item.id} className="flex items-center justify-between p-2 rounded-xl border border-dashed border-stone-100">
                  <div className="flex items-center gap-3">
                    <img src={item.imageUrl} className="w-10 h-10 rounded-lg object-cover" alt="" />
                    <div>
                      <p className="font-medium text-sm text-stone-700">{item.name}</p>
                      <p className="text-xs text-orange-800 font-bold">R$ {item.price.toFixed(2)}</p>
                    </div>
                  </div>
                  <div className="flex gap-1">
                    <button onClick={() => setEditingSweet({ sectionId: section.id, sweet: item })} className="p-1.5 text-stone-300 hover:text-orange-800">
                      <Edit2 size={16} />
                    </button>
                    <button onClick={() => deleteSweet(section.id, item.id)} className="p-1.5 text-stone-300 hover:text-orange-800">
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}

        {isAddingSection ? (
          <div className="flex gap-2 bg-stone-50 p-4 rounded-2xl animate-in fade-in zoom-in-95">
            <input 
              autoFocus
              className="flex-grow bg-white border border-stone-200 rounded-xl px-4 py-2 outline-none focus:ring-2 ring-orange-100 text-stone-800"
              placeholder="Nome da Seção (ex: Tortas)"
              value={newSectionTitle}
              onChange={e => setNewSectionTitle(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && addSection()}
            />
            <button onClick={addSection} className="bg-orange-800 text-white p-2 rounded-xl">
              <Check size={24} />
            </button>
            <button onClick={() => setIsAddingSection(false)} className="bg-stone-200 text-stone-500 p-2 rounded-xl">
              <X size={24} />
            </button>
          </div>
        ) : (
          <button 
            onClick={() => setIsAddingSection(true)}
            className="w-full py-4 border-2 border-dashed border-orange-200 text-orange-800/40 rounded-2xl flex items-center justify-center gap-2 hover:bg-orange-50 transition-colors"
          >
            <Plus size={20} /> Adicionar Nova Seção
          </button>
        )}
      </div>

      {editingSweet.sweet && (
        <div className="fixed inset-0 z-50 bg-stone-950/40 backdrop-blur-sm flex items-center justify-center p-4 overflow-y-auto">
          <div className="bg-[#FDF8F5] w-full max-w-md rounded-3xl p-6 shadow-2xl animate-in slide-in-from-bottom-8 my-auto">
            <h3 className="text-xl font-bold mb-6 flex items-center gap-2 text-stone-800">
              <Edit2 size={20} className="text-orange-800" />
              Editar Doce
            </h3>
            <div className="space-y-4">
              <div className="flex flex-col items-center gap-3">
                <div className="w-32 h-32 rounded-2xl overflow-hidden bg-white border-2 border-orange-100 relative group">
                  <img src={editingSweet.sweet.imageUrl} className="w-full h-full object-cover" alt="Preview" />
                  <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="absolute inset-0 bg-stone-900/40 text-white opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity"
                  >
                    <Upload size={24} />
                  </button>
                </div>
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="text-xs font-bold text-orange-800 hover:text-orange-900 flex items-center gap-1 uppercase tracking-wider"
                >
                  <Upload size={14} /> Alterar Foto
                </button>
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
              </div>

              <div>
                <label className="text-xs font-bold text-stone-400 uppercase ml-1 block">Nome</label>
                <input 
                  className="w-full bg-white border border-stone-200 rounded-xl px-4 py-3 mt-1 outline-none focus:ring-2 ring-orange-100 text-stone-800"
                  value={editingSweet.sweet.name}
                  onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, name: e.target.value } })}
                  placeholder="Nome do doce"
                />
              </div>

              <div>
                <label className="text-xs font-bold text-stone-400 uppercase ml-1 flex justify-between">
                  Descrição
                  <button 
                    onClick={helpWithDescription}
                    disabled={isGenerating || !editingSweet.sweet.name}
                    className="text-orange-800 hover:text-orange-950 flex items-center gap-1 normal-case font-medium disabled:opacity-50"
                  >
                    <Wand2 size={12} /> {isGenerating ? 'Gerando...' : 'IA'}
                  </button>
                </label>
                <textarea 
                  className="w-full bg-white border border-stone-200 rounded-xl px-4 py-3 mt-1 outline-none focus:ring-2 ring-orange-100 min-h-[80px] text-stone-800"
                  value={editingSweet.sweet.description}
                  onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, description: e.target.value } })}
                  placeholder="Descrição..."
                />
              </div>

              <div>
                <label className="text-xs font-bold text-stone-400 uppercase ml-1">Preço (R$)</label>
                <input 
                  type="number"
                  step="0.01"
                  className="w-full bg-white border border-stone-200 rounded-xl px-4 py-3 mt-1 outline-none focus:ring-2 ring-orange-100 text-stone-800"
                  value={editingSweet.sweet.price || ''}
                  onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, price: parseFloat(e.target.value) || 0 } })}
                  placeholder="0.00"
                />
              </div>
            </div>
            <div className="flex gap-3 mt-8">
              <button onClick={() => setEditingSweet({ sectionId: '', sweet: null })} className="flex-1 bg-stone-100 text-stone-600 font-bold py-3 rounded-xl hover:bg-stone-200 transition-colors">
                Cancelar
              </button>
              <button onClick={saveSweet} className="flex-1 bg-orange-800 text-white font-bold py-3 rounded-xl hover:bg-orange-900 transition-colors shadow-lg shadow-orange-100">
                Salvar Doce
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

