import React, { useState, useEffect } from 'react';
import { ShoppingBag, Settings, LogOut } from 'lucide-react';
import { Section, Sweet, CartItem } from './types';
import BrigadeiroLogo from './components/BrigadeiroLogo';
import SweetCard from './components/SweetCard';
import AdminPanel from './components/AdminPanel';
import CartSheet from './components/CartSheet';
import LoginForm from './components/LoginForm';

const INITIAL_DATA: Section[] = [
  {
    id: '1',
    title: 'Brigadeiros Gourmet',
    items: [
      { id: 'b1', name: 'Brigadeiro Tradicional', description: 'Chocolate belga 54% com granulado macio.', price: 4.5, imageUrl: 'https://images.unsplash.com/photo-1599599810769-bcde5a160d32?auto=format&fit=crop&q=80&w=400' },
      { id: 'b2', name: 'Ninho com Nutella', description: 'Massa de leite ninho recheada com Nutella pura.', price: 5.5, imageUrl: 'https://images.unsplash.com/photo-1548365328-8c6db3220e4c?auto=format&fit=crop&q=80&w=400' }
    ]
  },
  {
    id: '2',
    title: 'Fatias de Bolo',
    items: [
      { id: 'f1', name: 'Cenoura com Chocolate', description: 'Fatia generosa com cobertura de brigadeiro quente.', price: 12.0, imageUrl: 'https://images.unsplash.com/photo-1578985545062-69928b1d9587?auto=format&fit=crop&q=80&w=400' }
    ]
  }
];

const App: React.FC = () => {
  const [sections, setSections] = useState<Section[]>(() => {
    const saved = localStorage.getItem('doce-palato-sections');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isCartOpen, setIsCartOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('doce-palato-sections', JSON.stringify(sections));
  }, [sections]);

  const addToCart = (sweet: Sweet) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === sweet.id);
      if (existing) {
        return prev.map(item => item.id === sweet.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...sweet, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const clearCart = () => setCart([]);

  const handleToggleAdmin = () => {
    setIsAdminOpen(!isAdminOpen);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setIsAdminOpen(false);
  };

  return (
    <div className="min-h-screen pb-20 selection:bg-orange-100 selection:text-orange-900">
      {/* Header */}
      <header className="sticky top-0 z-40 bg-white/90 backdrop-blur-lg border-b border-orange-100 px-4 py-3 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => setIsAdminOpen(false)}>
          <BrigadeiroLogo size={42} />
          <div>
            <h1 className="font-logo text-xl text-orange-900 leading-none">Doce Palato</h1>
            <p className="text-[10px] text-orange-700 font-bold uppercase tracking-tighter">Sempre uma experiência inesquecível</p>
          </div>
        </div>

        <div className="flex items-center gap-2">
          {isLoggedIn && isAdminOpen && (
             <button 
              onClick={handleLogout}
              className="p-2 hover:bg-red-50 rounded-full transition-colors text-red-400"
              title="Sair"
           >
             <LogOut size={22} />
           </button>
          )}
          <button 
            onClick={handleToggleAdmin}
            className={`p-2 rounded-full transition-all ${isAdminOpen ? 'bg-orange-800 text-white' : 'hover:bg-orange-50 text-orange-700'}`}
            title="Gerenciar Cardápio"
          >
            <Settings size={22} />
          </button>
          <button 
            onClick={() => setIsCartOpen(true)}
            className="relative p-2 hover:bg-orange-50 rounded-full transition-all text-orange-800"
          >
            <ShoppingBag size={22} />
            {cart.length > 0 && (
              <span className="absolute -top-1 -right-1 bg-orange-700 text-white text-[9px] font-black w-5 h-5 flex items-center justify-center rounded-full border-2 border-white animate-in zoom-in">
                {cart.reduce((acc, item) => acc + item.quantity, 0)}
              </span>
            )}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-4xl mx-auto p-4 md:p-6 space-y-8">
        {isAdminOpen ? (
          isLoggedIn ? (
            <AdminPanel 
              sections={sections} 
              setSections={setSections} 
              onClose={() => setIsAdminOpen(false)} 
            />
          ) : (
            <LoginForm onLoginSuccess={() => setIsLoggedIn(true)} />
          )
        ) : (
          <div className="space-y-12">
            {/* Banner/Hero */}
            <div className="bg-gradient-to-br from-stone-800 to-orange-950 rounded-[2.5rem] p-8 text-white shadow-xl shadow-stone-200 flex flex-col md:flex-row items-center gap-6 overflow-hidden relative">
              <div className="relative z-10 flex-1 text-center md:text-left">
                <div className="mb-2 inline-block bg-orange-700/30 backdrop-blur-sm px-3 py-1 rounded-full border border-orange-500/20 text-[10px] font-bold uppercase tracking-widest text-orange-200">
                  Desde 2018 adoçando vidas
                </div>
                <h2 className="text-3xl font-bold mb-2">Bem-vindo(a)!</h2>
                <p className="opacity-90 text-sm max-w-sm mb-6">Sempre uma experiência inesquecível. Desde 2018, selecionamos os melhores ingredientes para criar doces que marcam sua história.</p>
                <div className="inline-flex items-center gap-2 bg-white/10 backdrop-blur-md px-4 py-2 rounded-full text-xs font-bold uppercase tracking-widest border border-white/20">
                  ✨ Feito à Mão com Amor
                </div>
              </div>
              <div className="relative z-10 scale-125 md:scale-150 transform rotate-12 transition-transform hover:rotate-0 duration-700">
                <BrigadeiroLogo size={120} />
              </div>
              <div className="absolute top-0 right-0 w-64 h-64 bg-orange-500/10 rounded-full -mr-20 -mt-20 blur-3xl"></div>
            </div>

            {sections.map(section => (
              <section key={section.id} className="animate-in fade-in slide-in-from-bottom-4 duration-700">
                <div className="flex items-center gap-3 mb-6">
                  <div className="h-8 w-1.5 bg-orange-700 rounded-full"></div>
                  <h2 className="text-2xl font-black text-stone-800 tracking-tight">
                    {section.title}
                  </h2>
                  <span className="text-xs font-bold text-stone-300 ml-auto uppercase tracking-widest">
                    {section.items.length} itens
                  </span>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {section.items.map(item => (
                    <SweetCard 
                      key={item.id} 
                      sweet={item} 
                      onAdd={() => addToCart(item)} 
                    />
                  ))}
                </div>
              </section>
            ))}
          </div>
        )}
      </main>

      <CartSheet 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        cart={cart}
        updateQuantity={updateQuantity}
        removeFromCart={removeFromCart}
        clearCart={clearCart}
      />

      {cart.length > 0 && !isCartOpen && !isAdminOpen && (
        <button 
          onClick={() => setIsCartOpen(true)}
          className="fixed bottom-6 left-1/2 -translate-x-1/2 z-30 bg-orange-700 text-white shadow-2xl shadow-orange-950/20 px-8 py-4 rounded-full flex items-center gap-3 font-bold hover:bg-orange-800 transition-all hover:scale-105 active:scale-95 whitespace-nowrap border-4 border-white"
        >
          <div className="bg-white/20 p-1 rounded-lg">
            <ShoppingBag size={20} />
          </div>
          <span>Ver Minha Comanda • R$ {cart.reduce((acc, item) => acc + (item.price * item.quantity), 0).toFixed(2)}</span>
        </button>
      )}

      {!isAdminOpen && (
        <footer className="mt-12 py-8 px-4 text-center">
          <p className="text-stone-400 text-[10px] font-bold uppercase tracking-[0.2em] mb-2">
            Doce Palato • Desde 2018
          </p>
          <p className="text-orange-800/40 text-[10px]">Sempre uma experiência inesquecível.</p>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { X, Minus, Plus, Trash2, Send, User, MessageSquare } from 'lucide-react';
import { CartItem } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  updateQuantity: (id: string, delta: number) => void;
  removeFromCart: (id: string) => void;
  clearCart: () => void;
}

const CartSheet: React.FC<Props> = ({ isOpen, onClose, cart, updateQuantity, removeFromCart, clearCart }) => {
  const [customerName, setCustomerName] = useState('');
  const [notes, setNotes] = useState('');

  if (!isOpen) return null;

  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const sendToWhatsApp = () => {
    if (!customerName.trim()) {
      alert('Por favor, informe seu nome para a comanda.');
      return;
    }

    const header = `*🤎 DOCE PALATO - DESDE 2018 🤎*\n_Sempre uma experiência inesquecível_\n`;
    const customer = `\n👤 *Cliente:* ${customerName}\n`;
    const items = cart.map(item => `• ${item.quantity}x ${item.name} (_R$ ${item.price.toFixed(2)} uni._)`).join('\n');
    const footer = `\n\n💰 *Total: R$ ${total.toFixed(2)}*`;
    const obs = notes.trim() ? `\n\n📝 *Observações:* ${notes}` : '';

    const message = `${header}${customer}\n*Itens:*\n${items}${obs}${footer}`;

    const encoded = encodeURIComponent(message);
    window.open(`https://wa.me/?text=${encoded}`, '_blank');
    clearCart();
    setCustomerName('');
    setNotes('');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex justify-end">
      <div 
        className="absolute inset-0 bg-stone-900/40 backdrop-blur-sm animate-in fade-in"
        onClick={onClose}
      />

      <div className="relative w-full max-w-md bg-[#FDF8F5] h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
        <div className="p-6 border-b flex items-center justify-between bg-white">
          <div>
            <h2 className="text-2xl font-bold text-stone-800">Sua Comanda</h2>
            <p className="text-xs text-orange-800 font-medium uppercase tracking-wider">Doce Palato • Desde 2018</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-stone-50 rounded-full text-stone-400 transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="flex-grow overflow-y-auto p-6 space-y-6">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-4">
              <div className="w-20 h-20 bg-stone-100 rounded-full flex items-center justify-center text-stone-300">
                <Trash2 size={40} />
              </div>
              <div>
                <p className="text-lg font-bold text-stone-700">Sacola vazia</p>
                <p className="text-stone-400">Escolha seus doces favoritos no cardápio!</p>
              </div>
            </div>
          ) : (
            <>
              <div className="space-y-4">
                {cart.map(item => (
                  <div key={item.id} className="flex gap-4 items-center p-3 rounded-2xl bg-white border border-stone-100 group shadow-sm">
                    <div className="w-14 h-14 rounded-xl overflow-hidden bg-stone-50 flex-shrink-0 border border-stone-100">
                      <img src={item.imageUrl} alt={item.name} className="w-full h-full object-cover" />
                    </div>
                    <div className="flex-grow">
                      <div className="flex justify-between items-start">
                        <h4 className="font-bold text-stone-800 text-sm leading-tight">{item.name}</h4>
                        <button onClick={() => removeFromCart(item.id)} className="text-stone-300 hover:text-orange-700 transition-colors ml-2">
                          <Trash2 size={16} />
                        </button>
                      </div>
                      <div className="flex items-center justify-between mt-1">
                        <span className="text-xs font-bold text-orange-800">R$ {(item.price * item.quantity).toFixed(2)}</span>
                        <div className="flex items-center bg-stone-50 rounded-lg p-0.5 border border-stone-100">
                          <button onClick={() => updateQuantity(item.id, -1)} className="p-1 text-orange-800 hover:bg-white rounded transition-colors">
                            <Minus size={12} />
                          </button>
                          <span className="w-6 text-center text-xs font-bold text-stone-700">{item.quantity}</span>
                          <button onClick={() => updateQuantity(item.id, 1)} className="p-1 text-orange-800 hover:bg-white rounded transition-colors">
                            <Plus size={12} />
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>

              <div className="space-y-4 pt-4 border-t border-dashed border-stone-200">
                <div>
                  <label className="text-xs font-bold text-stone-400 uppercase ml-1 flex items-center gap-1 mb-1">
                    <User size={12} /> Seu Nome
                  </label>
                  <input 
                    className="w-full bg-white border border-stone-200 rounded-xl px-4 py-3 outline-none focus:ring-2 ring-orange-100 text-stone-800 transition-all"
                    placeholder="Como podemos te chamar?"
                    value={customerName}
                    onChange={e => setCustomerName(e.target.value)}
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-stone-400 uppercase ml-1 flex items-center gap-1 mb-1">
                    <MessageSquare size={12} /> Observações
                  </label>
                  <textarea 
                    className="w-full bg-white border border-stone-200 rounded-xl px-4 py-3 outline-none focus:ring-2 ring-orange-100 text-stone-800 transition-all min-h-[60px]"
                    placeholder="Alguma alergia ou detalhe especial?"
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                  />
                </div>
              </div>
            </>
          )}
        </div>

        {cart.length > 0 && (
          <div className="p-6 border-t bg-white shadow-[0_-10px_20px_-5px_rgba(0,0,0,0.05)] space-y-4">
            <div className="flex justify-between items-end">
              <div>
                <p className="text-xs text-stone-400 font-bold uppercase">Valor Total</p>
