            <circle cx="70" cy="56" r="4.5" fill="#BC4A3C" className="animate-cheek" />
          </g>

          {/* Brilho de Reflexo Superior */}
          <path
            d="M35,30 Q50,18 65,30"
            stroke="white"
            strokeWidth="1.5"
            fill="none"
            opacity="0.2"
            strokeLinecap="round"
          />
        </g>
      </svg>
    </div>
  );
};

