import React, { useState, useRef } from 'react';
import { Plus, Trash2, Edit2, Check, X, Wand2, Upload, LayoutGrid, ListTree, ChevronRight } from 'lucide-react';
import { Section, Sweet } from '../types';
import { GoogleGenAI } from "@google/genai";

interface Props {
  sections: Section[];
  setSections: React.Dispatch<React.SetStateAction<Section[]>>;
  onClose: () => void;
}

const AdminPanel: React.FC<Props> = ({ sections, setSections, onClose }) => {
  const [activeTab, setActiveTab] = useState<string>('config'); // 'config' ou o ID da seção
  const [isAddingSection, setIsAddingSection] = useState(false);
  const [newSectionTitle, setNewSectionTitle] = useState('');
  const [editingSectionId, setEditingSectionId] = useState<string | null>(null);
  const [tempSectionTitle, setTempSectionTitle] = useState('');
  const [editingSweet, setEditingSweet] = useState<{ sectionId: string, sweet: Sweet | null }>({ sectionId: '', sweet: null });
  const [isGenerating, setIsGenerating] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const addSection = () => {
    if (!newSectionTitle.trim()) return;
    const newId = Date.now().toString();
    const newSection: Section = {
      id: newId,
      title: newSectionTitle,
      items: []
    };
    setSections([...sections, newSection]);
    setNewSectionTitle('');
    setIsAddingSection(false);
    setActiveTab(newId);
  };

  const startRenaming = (section: Section) => {
    setEditingSectionId(section.id);
    setTempSectionTitle(section.title);
  };

  const saveSectionName = () => {
    if (!tempSectionTitle.trim() || !editingSectionId) return;
    setSections(prev => prev.map(s => 
      s.id === editingSectionId ? { ...s, title: tempSectionTitle } : s
    ));
    setEditingSectionId(null);
  };

  const deleteSection = (id: string) => {
    if (confirm('Tem certeza que deseja remover esta seção e todos os seus doces?')) {
      setSections(sections.filter(s => s.id !== id));
      setActiveTab('config');
    }
  };

  const startAddSweet = (sectionId: string) => {
    setEditingSweet({ 
      sectionId, 
      sweet: { id: Date.now().toString(), name: '', description: '', price: 0, imageUrl: 'https://images.unsplash.com/photo-1570476922354-81227cdbb76c?q=80&w=400&h=300&auto=format&fit=crop' } 
    });
  };

  const saveSweet = () => {
    if (!editingSweet.sweet || !editingSweet.sweet.name) return;

    setSections(prev => prev.map(s => {
      if (s.id === editingSweet.sectionId) {
        const exists = s.items.find(item => item.id === editingSweet.sweet!.id);
        if (exists) {
          return { ...s, items: s.items.map(item => item.id === editingSweet.sweet!.id ? editingSweet.sweet! : item) };
        }
        return { ...s, items: [...s.items, editingSweet.sweet!] };
      }
      return s;
    }));
    setEditingSweet({ sectionId: '', sweet: null });
  };

  const deleteSweet = (sectionId: string, sweetId: string) => {
    setSections(prev => prev.map(s => {
      if (s.id === sectionId) {
        return { ...s, items: s.items.filter(item => item.id !== sweetId) };
      }
      return s;
    }));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editingSweet.sweet) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditingSweet({
          ...editingSweet,
          sweet: { ...editingSweet.sweet!, imageUrl: reader.result as string }
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const helpWithDescription = async () => {
    if (!editingSweet.sweet?.name) return;
    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Escreva uma descrição curta, irresistível e vendedora para um doce chamado "${editingSweet.sweet.name}". Use no máximo 15 palavras.`,
      });
      const desc = response.text || '';
      setEditingSweet(prev => prev.sweet ? ({
        ...prev,
        sweet: { ...prev.sweet, description: desc.trim().replace(/^"|"$/g, '') }
      }) : prev);
    } catch (e) {
      console.error(e);
    } finally {
      setIsGenerating(false);
    }
  };

  const activeSection = sections.find(s => s.id === activeTab);

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between border-b border-orange-100 pb-4">
        <div>
          <h2 className="text-2xl font-bold text-stone-800">Painel de Cadastro</h2>
          <p className="text-xs text-orange-800 font-bold uppercase tracking-widest">Doce Palato • Admin</p>
        </div>
        <button onClick={onClose} className="p-2 hover:bg-orange-50 rounded-full text-stone-400">
          <X size={24} />
        </button>
      </div>

      {/* Tabs Menu */}
      <div className="flex overflow-x-auto pb-2 gap-2 scrollbar-hide no-scrollbar">
        <button 
          onClick={() => setActiveTab('config')}
          className={`flex items-center gap-2 px-4 py-2 rounded-full whitespace-nowrap text-sm font-bold transition-all border-2 ${
            activeTab === 'config' 
            ? 'bg-orange-800 text-white border-orange-800 shadow-md' 
            : 'bg-white text-stone-500 border-stone-100 hover:border-orange-200'
          }`}
        >
          <ListTree size={16} /> Organizar Categorias
        </button>
        {sections.map(s => (
          <button 
            key={s.id}
            onClick={() => setActiveTab(s.id)}
            className={`flex items-center gap-2 px-4 py-2 rounded-full whitespace-nowrap text-sm font-bold transition-all border-2 ${
              activeTab === s.id 
              ? 'bg-orange-800 text-white border-orange-800 shadow-md' 
              : 'bg-white text-stone-500 border-stone-100 hover:border-orange-200'
            }`}
          >
            <LayoutGrid size={16} /> {s.title}
          </button>
        ))}
      </div>

      <div className="min-h-[400px]">
        {activeTab === 'config' ? (
          <div className="space-y-4 animate-in fade-in slide-in-from-left-4">
            <div className="bg-orange-50/50 p-6 rounded-3xl border border-orange-100 mb-6">
              <h4 className="font-bold text-stone-800 mb-2">Instruções</h4>
              <p className="text-xs text-stone-500 leading-relaxed">
                Aqui você define os títulos das categorias do seu cardápio.
                Você pode criar novas, excluir ou <strong>editar os nomes existentes</strong> clicando no ícone de lápis.
              </p>
            </div>

            <div className="grid gap-3">
              {sections.map(section => (
                <div key={section.id} className="flex items-center justify-between p-4 bg-white rounded-2xl border border-stone-100 shadow-sm transition-all hover:border-orange-100">
                  <div className="flex items-center gap-3 flex-grow">
                    <div className="w-10 h-10 bg-stone-50 rounded-full flex items-center justify-center text-orange-800 font-bold flex-shrink-0">
                      {section.items.length}
                    </div>

                    {editingSectionId === section.id ? (
                      <div className="flex gap-2 flex-grow mr-4">
                        <input 
                          autoFocus
                          className="bg-orange-50 px-3 py-1.5 rounded-lg outline-none text-stone-800 font-bold border border-orange-200 w-full"
                          value={tempSectionTitle}
                          onChange={e => setTempSectionTitle(e.target.value)}
                          onKeyDown={e => e.key === 'Enter' && saveSectionName()}
                        />
                        <button onClick={saveSectionName} className="text-green-600 p-1 hover:bg-green-50 rounded-md">
                          <Check size={20} />
                        </button>
                        <button onClick={() => setEditingSectionId(null)} className="text-red-400 p-1 hover:bg-red-50 rounded-md">
                          <X size={20} />
                        </button>
                      </div>
                    ) : (
                      <div className="flex-grow">
                        <p className="font-bold text-stone-800">{section.title}</p>
                        <p className="text-[10px] text-stone-400 uppercase font-bold tracking-tighter">Categoria Ativa</p>
                      </div>
                    )}
                  </div>

                  <div className="flex gap-1">
                    {editingSectionId !== section.id && (
                      <button 
                        onClick={() => startRenaming(section)}
                        className="p-2 text-stone-300 hover:text-orange-800 transition-colors"
                        title="Renomear Categoria"
                      >
                        <Edit2 size={18} />
                      </button>
                    )}
                    <button 
                      onClick={() => setActiveTab(section.id)}
                      className="p-2 text-stone-300 hover:text-orange-800 transition-colors"
                      title="Ver Itens"
                    >
                      <ChevronRight size={22} />
                    </button>
                    <button 
                      onClick={() => deleteSection(section.id)}
                      className="p-2 text-stone-300 hover:text-red-500 transition-colors"
                      title="Excluir Categoria"
                    >
                      <Trash2 size={18} />
                    </button>
                  </div>
                </div>
              ))}
            </div>

            {isAddingSection ? (
              <div className="flex gap-2 bg-white p-4 rounded-2xl border-2 border-orange-100 animate-in fade-in zoom-in-95 mt-4">
                <input 
                  autoFocus
                  className="flex-grow bg-transparent px-2 py-2 outline-none text-stone-800 font-medium"
                  placeholder="Nome da Categoria (ex: Doces Finos)"
                  value={newSectionTitle}
                  onChange={e => setNewSectionTitle(e.target.value)}
                  onKeyDown={e => e.key === 'Enter' && addSection()}
                />
                <button onClick={addSection} className="bg-orange-800 text-white p-2 rounded-xl">
                  <Check size={24} />
                </button>
                <button onClick={() => setIsAddingSection(false)} className="bg-stone-100 text-stone-500 p-2 rounded-xl">
                  <X size={24} />
                </button>
              </div>
            ) : (
              <button 
                onClick={() => setIsAddingSection(true)}
                className="w-full py-6 border-2 border-dashed border-orange-200 text-orange-800/60 rounded-3xl flex flex-col items-center justify-center gap-2 hover:bg-orange-50 transition-all group mt-4"
              >
                <div className="p-3 bg-white rounded-full shadow-sm group-hover:scale-110 transition-transform">
                  <Plus size={24} />
                </div>
                <span className="font-bold text-sm">Criar Nova Categoria</span>
              </button>
            )}
          </div>
        ) : (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <div className="flex items-center justify-between">
              <div>
                <h3 className="text-xl font-bold text-stone-800">{activeSection?.title}</h3>
                <p className="text-xs text-stone-400 font-bold uppercase tracking-wider">{activeSection?.items.length} itens cadastrados</p>
              </div>
              <button 
                onClick={() => activeSection && startAddSweet(activeSection.id)}
                className="bg-orange-800 text-white px-4 py-2 rounded-full text-xs font-bold flex items-center gap-2 hover:bg-orange-900 transition-all shadow-md active:scale-95"
              >
                <Plus size={16} /> Novo Doce nesta Aba
              </button>
            </div>

            <div className="grid grid-cols-1 gap-3">
              {activeSection?.items.length === 0 ? (
                <div className="py-20 text-center border-2 border-dashed border-stone-100 rounded-3xl">
                  <p className="text-stone-400 font-medium">Nenhum doce cadastrado nesta categoria.</p>
                  <p className="text-xs text-stone-300">Clique no botão acima para começar!</p>
                </div>
              ) : (
                activeSection?.items.map(item => (
                  <div key={item.id} className="flex items-center justify-between p-3 bg-white rounded-2xl border border-stone-100 shadow-sm hover:border-orange-100 transition-colors group">
                    <div className="flex items-center gap-4">
                      <div className="w-14 h-14 rounded-xl overflow-hidden bg-stone-50 border border-stone-100">
                        <img src={item.imageUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" alt="" />
                      </div>
                      <div>
                        <p className="font-bold text-stone-800">{item.name}</p>
                        <p className="text-sm font-black text-orange-800">R$ {item.price.toFixed(2)}</p>
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <button 
                        onClick={() => activeSection && setEditingSweet({ sectionId: activeSection.id, sweet: item })} 
                        className="p-2 text-stone-300 hover:text-orange-800 transition-colors"
                        title="Editar"
                      >
                        <Edit2 size={18} />
                      </button>
                      <button 
                        onClick={() => activeSection && deleteSweet(activeSection.id, item.id)} 
                        className="p-2 text-stone-300 hover:text-red-500 transition-colors"
                        title="Remover"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>

      {editingSweet.sweet && (
        <div className="fixed inset-0 z-[60] bg-stone-950/40 backdrop-blur-md flex items-center justify-center p-4 overflow-y-auto">
          <div className="bg-[#FDF8F5] w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in slide-in-from-bottom-8 my-auto border border-white">
            <h3 className="text-2xl font-black mb-8 flex items-center gap-3 text-stone-800">
              <div className="p-2 bg-orange-800 text-white rounded-xl shadow-lg">
                <Edit2 size={24} />
              </div>
              Detalhes do Doce
            </h3>

            <div className="space-y-5">
              <div className="flex flex-col items-center gap-3">
                <div className="w-32 h-32 rounded-3xl overflow-hidden bg-white border-2 border-orange-100 relative group shadow-inner">
                  <img src={editingSweet.sweet.imageUrl} className="w-full h-full object-cover" alt="Preview" />
                  <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="absolute inset-0 bg-stone-900/50 text-white opacity-0 group-hover:opacity-100 flex flex-col items-center justify-center transition-all duration-300 backdrop-blur-[2px]"
                  >
                    <Upload size={24} />
                    <span className="text-[10px] font-black uppercase mt-1">Upload</span>
                  </button>
                </div>
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="text-[10px] font-black text-orange-800 hover:text-orange-950 flex items-center gap-1 uppercase tracking-[0.2em]"
                >
                  Substituir Imagem
                </button>
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
              </div>

              <div>
                <label className="text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1 block mb-1">Nome do Produto</label>
                <input 
                  className="w-full bg-white border border-stone-100 rounded-2xl px-5 py-3 outline-none focus:ring-4 ring-orange-50 text-stone-800 font-bold transition-all shadow-sm"
                  value={editingSweet.sweet.name}
                  onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, name: e.target.value } })}
                  placeholder="Ex: Brigadeiro Belga"
                />
              </div>

              <div>
                <label className="text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1 flex justify-between items-center mb-1">
                  Descrição Irresistível
                  <button 
                    onClick={helpWithDescription}
                    disabled={isGenerating || !editingSweet.sweet.name}
                    className="bg-orange-50 text-orange-800 px-3 py-1 rounded-full text-[9px] font-black flex items-center gap-1 hover:bg-orange-800 hover:text-white transition-all disabled:opacity-30 border border-orange-100"
                  >
                    <Wand2 size={10} /> {isGenerating ? 'IA PENSANDO...' : 'USAR IA'}
                  </button>
                </label>
                <textarea 
                  className="w-full bg-white border border-stone-100 rounded-2xl px-5 py-4 outline-none focus:ring-4 ring-orange-50 min-h-[100px] text-stone-800 text-sm leading-relaxed transition-all shadow-sm"
                  value={editingSweet.sweet.description}
                  onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, description: e.target.value } })}
                  placeholder="Fale sobre os ingredientes e o sabor..."
                />
              </div>

              <div>
                <label className="text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1 block mb-1">Preço de Venda (R$)</label>
                <div className="relative">
                   <span className="absolute left-5 top-1/2 -translate-y-1/2 text-orange-800 font-black">R$</span>
                   <input 
                    type="number"
                    step="0.01"
                    className="w-full bg-white border border-stone-100 rounded-2xl pl-12 pr-5 py-4 outline-none focus:ring-4 ring-orange-50 text-stone-800 font-black text-xl shadow-sm"
                    value={editingSweet.sweet.price || ''}
                    onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, price: parseFloat(e.target.value) || 0 } })}
                    placeholder="0,00"
                  />
                </div>
              </div>
            </div>

            <div className="flex gap-4 mt-10">
              <button 
                onClick={() => setEditingSweet({ sectionId: '', sweet: null })} 
                className="flex-1 bg-stone-100 text-stone-500 font-black py-4 rounded-2xl hover:bg-stone-200 transition-all uppercase text-xs tracking-widest"
              >
                Descartar
              </button>
              <button 
                onClick={saveSweet} 
                className="flex-1 bg-orange-800 text-white font-black py-4 rounded-2xl hover:bg-orange-950 transition-all shadow-xl shadow-orange-100 uppercase text-xs tracking-widest"
              >
                Salvar Doce
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React from 'react';

interface Props {
  size?: number;
}

const BrigadeiroLogo: React.FC<Props> = ({ size = 64 }) => {
  return (
    <div className="relative inline-block" style={{ width: size, height: size }}>
      <style>
        {`
          @keyframes gourmet-float {
            0%, 100% { transform: translateY(0) rotate(0deg); }
            50% { transform: translateY(-10px) rotate(2deg); }
          }
          @keyframes eye-blink {
            0%, 90%, 100% { transform: scaleY(1); }
            95% { transform: scaleY(0.1); }
          }
