              <div className="flex gap-3 overflow-x-auto no-scrollbar pb-2">
                {sections.map(section => (
                  <button
                    key={section.id}
                    onClick={() => setActiveCategoryId(section.id)}
                    className={`px-6 py-3 rounded-2xl whitespace-nowrap text-sm font-bold transition-all duration-300 border-2 ${
                      activeCategoryId === section.id
                      ? 'bg-purple-800 text-white border-purple-800 shadow-lg shadow-purple-900/20 scale-105'
                      : 'bg-white text-purple-500 border-purple-100 hover:border-purple-300'
                    }`}
                  >
                    {section.title}
                  </button>
                ))}
              </div>
            </div>

            {/* Produtos da Categoria Selecionada */}
            <div key={activeCategoryId} className="animate-in fade-in slide-in-from-bottom-6 duration-700">
              {activeSection ? (
                <div className="space-y-8">
                   <div className="flex items-center gap-4">
                    <h3 className="text-3xl font-black text-purple-900 tracking-tight">{activeSection.title}</h3>
                    <div className="flex-grow h-[2px] bg-gradient-to-r from-purple-200 to-transparent"></div>
                  </div>

                  {activeSection.items.length > 0 ? (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                      {activeSection.items.map(item => (
                        <SweetCard 
                          key={item.id} 
                          sweet={item} 
                          onAdd={() => addToCart(item)} 
                        />
                      ))}
                    </div>
                  ) : (
                    <div className="bg-white rounded-[2rem] p-12 text-center border-2 border-dashed border-purple-100">
                      <p className="text-purple-300 font-bold mb-1">Nenhum doce aqui ainda.</p>
                      <p className="text-xs text-purple-200 uppercase tracking-widest">Estamos preparando novidades!</p>
                    </div>
                  )}
                </div>
              ) : (
                <div className="py-20 text-center">
                  <p className="text-purple-300 font-bold">Selecione uma categoria para ver os doces.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      <CartSheet 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        cart={cart}
        updateQuantity={updateQuantity}
        removeFromCart={removeFromCart}
        clearCart={clearCart}
      />

      {cart.length > 0 && !isCartOpen && !isAdminOpen && (
        <button 
          onClick={() => setIsCartOpen(true)}
          className="fixed bottom-8 left-1/2 -translate-x-1/2 z-30 bg-purple-800 text-white shadow-2xl shadow-purple-950/40 px-10 py-5 rounded-[2rem] flex items-center gap-4 font-black hover:bg-purple-900 transition-all hover:scale-105 active:scale-95 whitespace-nowrap border-4 border-white group"
        >
          <div className="bg-white/20 p-1.5 rounded-xl group-hover:rotate-12 transition-transform">
            <ShoppingBag size={24} />
