import React, { useState } from 'react';
import { X, Minus, Plus, Trash2, Send, User, MessageSquare } from 'lucide-react';
import { CartItem } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  updateQuantity: (id: string, delta: number) => void;
  removeFromCart: (id: string) => void;
  clearCart: () => void;
}

const CartSheet: React.FC<Props> = ({ isOpen, onClose, cart, updateQuantity, removeFromCart, clearCart }) => {
  const [customerName, setCustomerName] = useState('');
  const [notes, setNotes] = useState('');

  if (!isOpen) return null;

  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const sendToWhatsApp = () => {
    if (!customerName.trim()) {
      alert('Por favor, informe seu nome para a comanda.');
      return;
    }

    const header = `*💜 DOCE PALATO - DESDE 2018 💜*\n_Sempre uma experiência inesquecível_\n`;
    const customer = `\n👤 *Cliente:* ${customerName}\n`;
    const items = cart.map(item => `• ${item.quantity}x ${item.name} (_R$ ${item.price.toFixed(2)} uni._)`).join('\n');
    const footer = `\n\n💰 *Total: R$ ${total.toFixed(2)}*`;
    const obs = notes.trim() ? `\n\n📝 *Observações:* ${notes}` : '';

    const message = `${header}${customer}\n*Itens:*\n${items}${obs}${footer}`;

    const encoded = encodeURIComponent(message);
    window.open(`https://wa.me/?text=${encoded}`, '_blank');
    clearCart();
    setCustomerName('');
    setNotes('');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex justify-end">
      <div 
        className="absolute inset-0 bg-purple-900/40 backdrop-blur-sm animate-in fade-in"
        onClick={onClose}
      />

      <div className="relative w-full max-w-md bg-[#FAF5FF] h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
        <div className="p-6 border-b flex items-center justify-between bg-white">
          <div>
            <h2 className="text-2xl font-bold text-purple-900">Sua Comanda</h2>
            <p className="text-xs text-purple-700 font-medium uppercase tracking-wider">Doce Palato • Desde 2018</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-purple-50 rounded-full text-purple-400 transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="flex-grow overflow-y-auto p-6 space-y-6">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-4">
              <div className="w-20 h-20 bg-purple-50 rounded-full flex items-center justify-center text-purple-200">
                <Trash2 size={40} />
              </div>
              <div>
                <p className="text-lg font-bold text-purple-800">Sacola vazia</p>
                <p className="text-purple-400">Escolha seus doces favoritos!</p>
              </div>
            </div>
          ) : (
            <>
              <div className="space-y-4">
                {cart.map(item => (
                  <div key={item.id} className="flex gap-4 items-center p-3 rounded-2xl bg-white border border-purple-100 group shadow-sm">
                    <div className="w-14 h-14 rounded-xl overflow-hidden bg-purple-50 flex-shrink-0 border border-purple-100">
                      <img src={item.imageUrl} alt={item.name} className="w-full h-full object-cover" />
                    </div>
                    <div className="flex-grow">
                      <div className="flex justify-between items-start">
                        <h4 className="font-bold text-purple-900 text-sm leading-tight">{item.name}</h4>
                        <button onClick={() => removeFromCart(item.id)} className="text-purple-300 hover:text-purple-700 transition-colors ml-2">
                          <Trash2 size={16} />
                        </button>
                      </div>
                      <div className="flex items-center justify-between mt-1">
                        <span className="text-xs font-bold text-purple-700">R$ {(item.price * item.quantity).toFixed(2)}</span>
                        <div className="flex items-center bg-purple-50 rounded-lg p-0.5 border border-purple-100">
                          <button onClick={() => updateQuantity(item.id, -1)} className="p-1 text-purple-800 hover:bg-white rounded transition-colors">
                            <Minus size={12} />
                          </button>
                          <span className="w-6 text-center text-xs font-bold text-purple-900">{item.quantity}</span>
                          <button onClick={() => updateQuantity(item.id, 1)} className="p-1 text-purple-800 hover:bg-white rounded transition-colors">
                            <Plus size={12} />
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>

              <div className="space-y-4 pt-4 border-t border-dashed border-purple-200">
                <div>
                  <label className="text-xs font-bold text-purple-400 uppercase ml-1 flex items-center gap-1 mb-1">
                    <User size={12} /> Seu Nome
                  </label>
                  <input 
                    className="w-full bg-white border border-purple-200 rounded-xl px-4 py-3 outline-none focus:ring-2 ring-purple-100 text-purple-900 transition-all"
                    placeholder="Como podemos te chamar?"
                    value={customerName}
                    onChange={e => setCustomerName(e.target.value)}
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-purple-400 uppercase ml-1 flex items-center gap-1 mb-1">
                    <MessageSquare size={12} /> Observações
                  </label>
                  <textarea 
                    className="w-full bg-white border border-purple-200 rounded-xl px-4 py-3 outline-none focus:ring-2 ring-purple-100 text-purple-900 transition-all min-h-[60px]"
                    placeholder="Deseja algum detalhe especial?"
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                  />
                </div>
              </div>
            </>
          )}
        </div>

        {cart.length > 0 && (
          <div className="p-6 border-t bg-white shadow-[0_-10px_20px_-5px_rgba(0,0,0,0.05)] space-y-4">
            <div className="flex justify-between items-end">
              <div>
                <p className="text-xs text-purple-400 font-bold uppercase">Valor Total</p>
                <p className="text-3xl font-bold text-purple-800">R$ {total.toFixed(2)}</p>
              </div>
            </div>
            <button 
              onClick={sendToWhatsApp}
              className="w-full bg-purple-700 text-white font-bold py-4 rounded-2xl flex items-center justify-center gap-3 hover:bg-purple-800 transition-all shadow-lg shadow-purple-100 active:scale-[0.98]"
            >
              <Send size={20} />
              Enviar Comanda via WhatsApp
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

