};

export default App;

import React, { useState, useRef } from 'react';
import { Plus, Trash2, Edit2, Check, X, Wand2, Upload, LayoutGrid, ListTree, ChevronRight, Phone } from 'lucide-react';
import { Section, Sweet } from '../types';
import { GoogleGenAI } from "@google/genai";

interface Props {
  sections: Section[];
  setSections: React.Dispatch<React.SetStateAction<Section[]>>;
  whatsappNumber: string;
  setWhatsappNumber: (val: string) => void;
  onClose: () => void;
}

const AdminPanel: React.FC<Props> = ({ sections, setSections, whatsappNumber, setWhatsappNumber, onClose }) => {
  const [activeTab, setActiveTab] = useState<string>('config'); 
  const [isAddingSection, setIsAddingSection] = useState(false);
  const [newSectionTitle, setNewSectionTitle] = useState('');
  const [editingSectionId, setEditingSectionId] = useState<string | null>(null);
  const [tempSectionTitle, setTempSectionTitle] = useState('');
  const [editingSweet, setEditingSweet] = useState<{ sectionId: string, sweet: Sweet | null }>({ sectionId: '', sweet: null });
  const [isGenerating, setIsGenerating] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const addSection = () => {
    if (!newSectionTitle.trim()) return;
    const newId = Date.now().toString();
    const newSection: Section = {
      id: newId,
      title: newSectionTitle,
      items: []
    };
    setSections([...sections, newSection]);
    setNewSectionTitle('');
    setIsAddingSection(false);
    setActiveTab(newId);
  };

  const startRenaming = (section: Section) => {
    setEditingSectionId(section.id);
    setTempSectionTitle(section.title);
  };

  const saveSectionName = () => {
    if (!tempSectionTitle.trim() || !editingSectionId) return;
    setSections(prev => prev.map(s => 
      s.id === editingSectionId ? { ...s, title: tempSectionTitle } : s
    ));
    setEditingSectionId(null);
  };

  const deleteSection = (id: string) => {
    if (confirm('Tem certeza que deseja remover esta seção e todos os seus doces?')) {
      setSections(sections.filter(s => s.id !== id));
      setActiveTab('config');
    }
  };

  const startAddSweet = (sectionId: string) => {
    setEditingSweet({ 
      sectionId, 
      sweet: { id: Date.now().toString(), name: '', description: '', price: 0, imageUrl: 'https://images.unsplash.com/photo-1570476922354-81227cdbb76c?q=80&w=400&h=300&auto=format&fit=crop' } 
    });
  };

  const saveSweet = () => {
    if (!editingSweet.sweet || !editingSweet.sweet.name) return;

    setSections(prev => prev.map(s => {
      if (s.id === editingSweet.sectionId) {
        const exists = s.items.find(item => item.id === editingSweet.sweet!.id);
        if (exists) {
          return { ...s, items: s.items.map(item => item.id === editingSweet.sweet!.id ? editingSweet.sweet! : item) };
        }
        return { ...s, items: [...s.items, editingSweet.sweet!] };
      }
      return s;
    }));
    setEditingSweet({ sectionId: '', sweet: null });
  };

  const deleteSweet = (sectionId: string, sweetId: string) => {
    setSections(prev => prev.map(s => {
      if (sectionId === s.id) {
        return { ...s, items: s.items.filter(item => item.id !== sweetId) };
      }
      return s;
    }));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editingSweet.sweet) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditingSweet({
          ...editingSweet,
          sweet: { ...editingSweet.sweet!, imageUrl: reader.result as string }
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const helpWithDescription = async () => {
    if (!editingSweet.sweet?.name) return;
    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Escreva uma descrição curta, irresistível e vendedora para um doce chamado "${editingSweet.sweet.name}". Use no máximo 15 palavras.`,
      });
      const desc = response.text || '';
      setEditingSweet(prev => prev.sweet ? ({
        ...prev,
        sweet: { ...prev.sweet, description: desc.trim().replace(/^"|"$/g, '') }
      }) : prev);
    } catch (e) {
      console.error(e);
    } finally {
      setIsGenerating(false);
    }
  };

  const activeSection = sections.find(s => s.id === activeTab);

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between border-b border-purple-100 pb-4">
        <div>
          <h2 className="text-2xl font-bold text-purple-900">Painel de Cadastro</h2>
          <p className="text-xs text-purple-800 font-bold uppercase tracking-widest">Doce Palato • Admin</p>
        </div>
        <button onClick={onClose} className="p-2 hover:bg-purple-50 rounded-full text-purple-400 transition-colors">
          <X size={24} />
        </button>
      </div>

      <div className="flex overflow-x-auto pb-2 gap-2 no-scrollbar">
        <button 
          onClick={() => setActiveTab('config')}
          className={`flex items-center gap-2 px-4 py-2 rounded-full whitespace-nowrap text-sm font-bold transition-all border-2 ${
            activeTab === 'config' 
            ? 'bg-purple-800 text-white border-purple-800 shadow-md' 
            : 'bg-white text-purple-500 border-purple-100 hover:border-purple-200'
          }`}
        >
          <ListTree size={16} /> Configurações Gerais
        </button>
        {sections.map(s => (
          <button 
            key={s.id}
            onClick={() => setActiveTab(s.id)}
            className={`flex items-center gap-2 px-4 py-2 rounded-full whitespace-nowrap text-sm font-bold transition-all border-2 ${
              activeTab === s.id 
              ? 'bg-purple-800 text-white border-purple-800 shadow-md' 
              : 'bg-white text-purple-500 border-purple-100 hover:border-purple-200'
            }`}
          >
            <LayoutGrid size={16} /> {s.title}
          </button>
        ))}
      </div>

      <div className="min-h-[400px]">
        {activeTab === 'config' ? (
          <div className="space-y-8 animate-in fade-in slide-in-from-left-4">

            {/* WhatsApp Config Section */}
            <div className="bg-white p-6 rounded-[2rem] border border-purple-100 shadow-sm space-y-4">
              <div className="flex items-center gap-3 mb-2">
                <div className="p-2 bg-green-50 text-green-600 rounded-xl">
                   <Phone size={20} />
                </div>
                <div>
                  <h4 className="font-bold text-purple-900">Recebimento de Pedidos</h4>
                  <p className="text-[10px] text-purple-400 font-bold uppercase tracking-widest">Configuração do WhatsApp</p>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-xs font-bold text-purple-500 ml-1">Número para Envio da Comanda</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-purple-300 font-bold">+</span>
                  <input 
                    type="text"
                    className="w-full bg-purple-50/30 border border-purple-100 rounded-2xl pl-8 pr-4 py-4 outline-none focus:ring-4 ring-purple-100 text-purple-900 font-bold transition-all"
                    placeholder="55 (DDD) 99999-9999"
                    value={whatsappNumber}
                    onChange={e => setWhatsappNumber(e.target.value)}
                  />
                </div>
                <p className="text-[10px] text-purple-300 ml-1">
                  Insira o código do país (55 para Brasil) + DDD + Número.
                </p>
              </div>
            </div>

            <div className="bg-purple-50/50 p-6 rounded-[2rem] border border-purple-100">
              <h4 className="font-bold text-purple-900 mb-2">Gerenciar Categorias (Abas)</h4>
              <p className="text-xs text-purple-700 leading-relaxed mb-6">
                Organize seu cardápio criando ou renomeando as abas de produtos.
              </p>

              <div className="grid gap-3">
                {sections.map(section => (
                  <div key={section.id} className="flex items-center justify-between p-4 bg-white rounded-2xl border border-purple-100 shadow-sm transition-all hover:border-purple-300">
                    <div className="flex items-center gap-3 flex-grow">
                      <div className="w-10 h-10 bg-purple-50 rounded-full flex items-center justify-center text-purple-800 font-bold flex-shrink-0">
                        {section.items.length}
                      </div>

                      {editingSectionId === section.id ? (
                        <div className="flex gap-2 flex-grow mr-4">
                          <input 
                            autoFocus
                            className="bg-purple-50 px-3 py-1.5 rounded-lg outline-none text-purple-900 font-bold border border-purple-200 w-full"
                            value={tempSectionTitle}
                            onChange={e => setTempSectionTitle(e.target.value)}
                            onKeyDown={e => e.key === 'Enter' && saveSectionName()}
                          />
                          <button onClick={saveSectionName} className="text-green-600 p-1 hover:bg-green-50 rounded-md">
                            <Check size={20} />
                          </button>
                          <button onClick={() => setEditingSectionId(null)} className="text-red-400 p-1 hover:bg-red-50 rounded-md">
                            <X size={20} />
                          </button>
                        </div>
                      ) : (
                        <div className="flex-grow">
                          <p className="font-bold text-purple-900">{section.title}</p>
                        </div>
                      )}
                    </div>

                    <div className="flex gap-1">
                      {editingSectionId !== section.id && (
                        <button 
                          onClick={() => startRenaming(section)}
                          className="p-2 text-purple-200 hover:text-purple-800 transition-colors"
                          title="Renomear"
                        >
                          <Edit2 size={18} />
                        </button>
                      )}
                      <button 
                        onClick={() => setActiveTab(section.id)}
                        className="p-2 text-purple-200 hover:text-purple-800 transition-colors"
                        title="Ver Doces"
                      >
                        <ChevronRight size={22} />
                      </button>
                      <button 
                        onClick={() => deleteSection(section.id)}
                        className="p-2 text-purple-200 hover:text-red-500 transition-colors"
                        title="Excluir"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </div>
                ))}
              </div>

              {isAddingSection ? (
                <div className="flex gap-2 bg-white p-4 rounded-2xl border-2 border-purple-100 animate-in fade-in zoom-in-95 mt-4">
                  <input 
                    autoFocus
                    className="flex-grow bg-transparent px-2 py-2 outline-none text-purple-900 font-medium"
                    placeholder="Nome da Nova Aba"
                    value={newSectionTitle}
                    onChange={e => setNewSectionTitle(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && addSection()}
                  />
                  <button onClick={addSection} className="bg-purple-800 text-white p-2 rounded-xl">
                    <Check size={24} />
                  </button>
                  <button onClick={() => setIsAddingSection(false)} className="bg-purple-100 text-purple-500 p-2 rounded-xl">
                    <X size={24} />
                  </button>
                </div>
              ) : (
                <button 
                  onClick={() => setIsAddingSection(true)}
                  className="w-full py-6 border-2 border-dashed border-purple-200 text-purple-800/60 rounded-3xl flex flex-col items-center justify-center gap-2 hover:bg-purple-50 transition-all group mt-4"
                >
                  <div className="p-3 bg-white rounded-full shadow-sm group-hover:scale-110 transition-transform">
                    <Plus size={24} />
                  </div>
                  <span className="font-bold text-sm">Criar Nova Aba</span>
                </button>
              )}
            </div>
          </div>
        ) : (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <div className="flex items-center justify-between">
              <div>
                <h3 className="text-xl font-bold text-purple-900">{activeSection?.title}</h3>
                <p className="text-xs text-purple-400 font-bold uppercase tracking-wider">{activeSection?.items.length} itens cadastrados</p>
              </div>
              <button 
                onClick={() => activeSection && startAddSweet(activeSection.id)}
                className="bg-purple-800 text-white px-4 py-2 rounded-full text-xs font-bold flex items-center gap-2 hover:bg-purple-900 transition-all shadow-md active:scale-95"
              >
                <Plus size={16} /> Adicionar Doce Aqui
              </button>
            </div>

            <div className="grid grid-cols-1 gap-3">
              {activeSection?.items.length === 0 ? (
                <div className="py-20 text-center border-2 border-dashed border-purple-100 rounded-3xl">
                  <p className="text-purple-300 font-medium">Nenhum doce nesta aba.</p>
                </div>
              ) : (
                activeSection?.items.map(item => (
                  <div key={item.id} className="flex items-center justify-between p-3 bg-white rounded-2xl border border-purple-100 shadow-sm hover:border-purple-300 transition-colors group">
                    <div className="flex items-center gap-4">
                      <div className="w-14 h-14 rounded-xl overflow-hidden bg-purple-50 border border-purple-100">
                        <img src={item.imageUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" alt="" />
                      </div>
                      <div>
                        <p className="font-bold text-purple-900">{item.name}</p>
                        <p className="text-sm font-black text-purple-700">R$ {item.price.toFixed(2)}</p>
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <button 
                        onClick={() => activeSection && setEditingSweet({ sectionId: activeSection.id, sweet: item })} 
                        className="p-2 text-purple-200 hover:text-purple-800 transition-colors"
                        title="Editar"
                      >
                        <Edit2 size={18} />
                      </button>
                      <button 
                        onClick={() => activeSection && deleteSweet(activeSection.id, item.id)} 
                        className="p-2 text-purple-200 hover:text-red-500 transition-colors"
                        title="Remover"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>

      {editingSweet.sweet && (
        <div className="fixed inset-0 z-[60] bg-purple-950/40 backdrop-blur-md flex items-center justify-center p-4 overflow-y-auto">
          <div className="bg-[#FAF5FF] w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in slide-in-from-bottom-8 my-auto border border-white">
            <h3 className="text-2xl font-black mb-8 flex items-center gap-3 text-purple-900">
              <div className="p-2 bg-purple-800 text-white rounded-xl shadow-lg">
                <Edit2 size={24} />
              </div>
