            </h3>

            <div className="space-y-5">
              <div className="flex flex-col items-center gap-3">
                <div className="w-32 h-32 rounded-3xl overflow-hidden bg-white border-2 border-purple-100 relative group shadow-inner">
                  <img src={editingSweet.sweet.imageUrl} className="w-full h-full object-cover" alt="Preview" />
                  <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="absolute inset-0 bg-purple-900/50 text-white opacity-0 group-hover:opacity-100 flex flex-col items-center justify-center transition-all duration-300 backdrop-blur-[2px]"
                  >
                    <Upload size={24} />
                    <span className="text-[10px] font-black uppercase mt-1">Upload</span>
                  </button>
                </div>
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
              </div>

              <div>
                <label className="text-[10px] font-black text-purple-400 uppercase tracking-widest ml-1 block mb-1">Nome do Produto</label>
                <input 
