    ]
  }
];

const App: React.FC = () => {
  const [sections, setSections] = useState<Section[]>(() => {
    const saved = localStorage.getItem('doce-palato-sections');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  const [whatsappNumber, setWhatsappNumber] = useState<string>(() => {
    return localStorage.getItem('doce-palato-whatsapp') || '';
  });

  const [cart, setCart] = useState<CartItem[]>([]);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [activeCategoryId, setActiveCategoryId] = useState<string>('');

  useEffect(() => {
    if (sections.length > 0 && !activeCategoryId) {
      setActiveCategoryId(sections[0].id);
    }
  }, [sections]);

  useEffect(() => {
    localStorage.setItem('doce-palato-sections', JSON.stringify(sections));
  }, [sections]);

  useEffect(() => {
    localStorage.setItem('doce-palato-whatsapp', whatsappNumber);
  }, [whatsappNumber]);

  const activeSection = useMemo(() => 
    sections.find(s => s.id === activeCategoryId), 
    [sections, activeCategoryId]
  );

  const addToCart = (sweet: Sweet) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === sweet.id);
      if (existing) {
        return prev.map(item => item.id === sweet.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...sweet, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const clearCart = () => setCart([]);

  const handleToggleAdmin = () => {
    setIsAdminOpen(!isAdminOpen);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setIsAdminOpen(false);
  };

  return (
    <div className="min-h-screen pb-32 selection:bg-rose-100 selection:text-rose-900 bg-[#FFF1F2]">
      {/* Header */}
      <header className="sticky top-0 z-40 bg-white/80 backdrop-blur-xl border-b border-rose-100 px-4 py-3 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => setIsAdminOpen(false)}>
          <BrigadeiroLogo size={42} />
          <div>
            <h1 className="font-logo text-xl text-rose-900 leading-none">Doce Palato</h1>
            <p className="text-[10px] text-rose-700 font-bold uppercase tracking-tighter">Sempre uma experiência inesquecível</p>
          </div>
        </div>

        <div className="flex items-center gap-2">
          {isLoggedIn && isAdminOpen && (
             <button 
              onClick={handleLogout}
              className="p-2 hover:bg-red-50 rounded-full transition-colors text-red-500"
              title="Sair"
           >
             <LogOut size={22} />
           </button>
          )}
          <button 
            onClick={handleToggleAdmin}
            className={`p-2 rounded-full transition-all ${isAdminOpen ? 'bg-rose-700 text-white shadow-inner' : 'hover:bg-rose-50 text-rose-700'}`}
            title="Gerenciar Cardápio"
          >
            <Settings size={22} />
          </button>
          <button 
            onClick={() => setIsCartOpen(true)}
            className="relative p-2 hover:bg-rose-50 rounded-full transition-all text-rose-800"
          >
            <ShoppingBag size={22} />
            {cart.length > 0 && (
              <span className="absolute -top-1 -right-1 bg-rose-700 text-white text-[9px] font-black w-5 h-5 flex items-center justify-center rounded-full border-2 border-white animate-in zoom-in">
                {cart.reduce((acc, item) => acc + item.quantity, 0)}
              </span>
            )}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-4xl mx-auto px-4 md:px-6 py-8 space-y-12">
        {isAdminOpen ? (
          isLoggedIn ? (
            <AdminPanel 
              sections={sections} 
              setSections={setSections} 
              whatsappNumber={whatsappNumber}
              setWhatsappNumber={setWhatsappNumber}
              onClose={() => setIsAdminOpen(false)} 
            />
          ) : (
            <LoginForm onLoginSuccess={() => setIsLoggedIn(true)} />
          )
        ) : (
          <div className="space-y-10">
            {/* Banner/Hero */}
            <div className="bg-gradient-to-br from-rose-700 to-red-900 rounded-[3rem] p-10 text-white shadow-2xl shadow-rose-300 flex flex-col md:flex-row items-center gap-8 overflow-hidden relative border-4 border-white/10">
              <div className="relative z-10 flex-1 text-center md:text-left">
                <div className="mb-4 inline-block bg-rose-500/30 backdrop-blur-md px-4 py-1.5 rounded-full border border-rose-300/30 text-[11px] font-bold uppercase tracking-widest text-rose-50">
                  Adoçando sua história desde 2018
                </div>
                <h2 className="text-4xl md:text-5xl font-black mb-4 tracking-tight leading-tight">Um amor em cada <span className="text-pink-300">mordida</span></h2>
                <p className="opacity-80 text-base max-w-sm mb-8 font-medium">Doces artesanais feitos com o coração. Explore nosso cardápio e apaixone-se pelo sabor.</p>
                <div className="flex flex-wrap gap-4 justify-center md:justify-start">
                  <div className="flex items-center gap-2 bg-white/5 px-4 py-2 rounded-full text-xs font-bold uppercase tracking-widest border border-white/10">
                    🍓 Frutas Frescas
                  </div>
                  <div className="flex items-center gap-2 bg-white/5 px-4 py-2 rounded-full text-xs font-bold uppercase tracking-widest border border-white/10">
                    ❤️ Feito com Amor
                  </div>
                </div>
              </div>
              <div className="relative z-10 transform hover:scale-110 duration-700 transition-all drop-shadow-[0_20px_40px_rgba(0,0,0,0.4)]">
                <BrigadeiroLogo size={160} />
              </div>
              <div className="absolute -bottom-20 -left-20 w-80 h-80 bg-rose-400/20 rounded-full blur-[100px]"></div>
            </div>

            {/* Categorias */}
            <div className="sticky top-20 z-30 -mx-4 px-4 py-4 bg-[#FFF1F2]/80 backdrop-blur-md">
              <div className="flex gap-3 overflow-x-auto no-scrollbar pb-2">
                {sections.map(section => (
                  <button
                    key={section.id}
                    onClick={() => setActiveCategoryId(section.id)}
                    className={`px-6 py-3 rounded-2xl whitespace-nowrap text-sm font-bold transition-all duration-300 border-2 ${
                      activeCategoryId === section.id
                      ? 'bg-rose-700 text-white border-rose-700 shadow-lg shadow-rose-900/20 scale-105'
                      : 'bg-white text-rose-500 border-rose-100 hover:border-rose-300'
                    }`}
                  >
                    {section.title}
                  </button>
                ))}
              </div>
            </div>

            {/* Produtos */}
            <div key={activeCategoryId} className="animate-in fade-in slide-in-from-bottom-6 duration-700">
              {activeSection ? (
                <div className="space-y-8">
                   <div className="flex items-center gap-4">
                    <h3 className="text-3xl font-black text-rose-900 tracking-tight">{activeSection.title}</h3>
                    <div className="flex-grow h-[2px] bg-gradient-to-r from-rose-200 to-transparent"></div>
                  </div>

                  {activeSection.items.length > 0 ? (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                      {activeSection.items.map(item => (
                        <SweetCard 
                          key={item.id} 
                          sweet={item} 
                          onAdd={() => addToCart(item)} 
                        />
                      ))}
                    </div>
                  ) : (
                    <div className="bg-white rounded-[2rem] p-12 text-center border-2 border-dashed border-rose-100">
                      <p className="text-rose-300 font-bold mb-1">Nenhum item nesta aba.</p>
                      <p className="text-xs text-rose-200 uppercase tracking-widest">Em breve novas delícias!</p>
                    </div>
                  )}
                </div>
              ) : (
                <div className="py-20 text-center">
                  <p className="text-rose-300 font-bold">Selecione uma categoria.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      <CartSheet 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        cart={cart}
        whatsappNumber={whatsappNumber}
        updateQuantity={updateQuantity}
        removeFromCart={removeFromCart}
        clearCart={clearCart}
      />

      {cart.length > 0 && !isCartOpen && !isAdminOpen && (
        <button 
          onClick={() => setIsCartOpen(true)}
          className="fixed bottom-8 left-1/2 -translate-x-1/2 z-30 bg-rose-700 text-white shadow-2xl shadow-rose-950/40 px-10 py-5 rounded-[2rem] flex items-center gap-4 font-black hover:bg-rose-800 transition-all hover:scale-105 active:scale-95 whitespace-nowrap border-4 border-white group"
        >
          <div className="bg-white/20 p-1.5 rounded-xl group-hover:rotate-12 transition-transform">
            <ShoppingBag size={24} />
          </div>
          <div className="text-left leading-tight">
            <span className="block text-[10px] uppercase opacity-70">Minha Comanda</span>
            <span className="text-lg">R$ {cart.reduce((acc, item) => acc + (item.price * item.quantity), 0).toFixed(2)}</span>
          </div>
          <ChevronRight size={20} className="ml-2 opacity-50" />
        </button>
      )}

      {!isAdminOpen && (
        <footer className="mt-20 py-12 px-4 text-center border-t border-rose-50 bg-white/50">
          <BrigadeiroLogo size={40} />
          <p className="text-rose-400 text-[11px] font-bold uppercase tracking-[0.3em] mt-4 mb-2">
            Doce Palato • Desde 2018
          </p>
          <p className="text-rose-800/30 text-[10px] font-medium">Sempre uma experiência inesquecível.</p>
        </footer>
      )}
    </div>
  );
};

