        <button 
          onClick={() => setActiveTab('config')}
          className={`flex items-center gap-2 px-4 py-2 rounded-full whitespace-nowrap text-sm font-bold transition-all border-2 ${
            activeTab === 'config' 
            ? 'bg-rose-700 text-white border-rose-700 shadow-md' 
            : 'bg-white text-rose-500 border-rose-100 hover:border-rose-200'
          }`}
        >
          <ListTree size={16} /> Geral
        </button>
        {sections.map(s => (
          <button 
            key={s.id}
            onClick={() => setActiveTab(s.id)}
            className={`flex items-center gap-2 px-4 py-2 rounded-full whitespace-nowrap text-sm font-bold transition-all border-2 ${
              activeTab === s.id 
              ? 'bg-rose-700 text-white border-rose-700 shadow-md' 
              : 'bg-white text-rose-500 border-rose-100 hover:border-rose-200'
            }`}
          >
            <LayoutGrid size={16} /> {s.title}
          </button>
        ))}
      </div>

      <div className="min-h-[400px]">
        {activeTab === 'config' ? (
          <div className="space-y-8 animate-in fade-in slide-in-from-left-4">

            {/* WhatsApp Config Section */}
            <div className="bg-white p-6 rounded-[2rem] border border-rose-100 shadow-sm space-y-4">
              <div className="flex items-center gap-3 mb-2">
                <div className="p-2 bg-green-50 text-green-600 rounded-xl">
                   <Phone size={20} />
                </div>
                <div>
                  <h4 className="font-bold text-rose-900">WhatsApp de Pedidos</h4>
                  <p className="text-[10px] text-rose-400 font-bold uppercase tracking-widest">Destinatário das Comandas</p>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-xs font-bold text-rose-500 ml-1">Número Destino</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-rose-300 font-bold">+</span>
                  <input 
                    type="text"
                    className="w-full bg-rose-50/30 border border-rose-100 rounded-2xl pl-8 pr-4 py-4 outline-none focus:ring-4 ring-rose-100 text-rose-900 font-bold transition-all"
                    placeholder="55 (DDD) 99999-9999"
                    value={whatsappNumber}
                    onChange={e => setWhatsappNumber(e.target.value)}
                  />
                </div>
              </div>
            </div>

            <div className="bg-rose-50/50 p-6 rounded-[2rem] border border-rose-100">
              <h4 className="font-bold text-rose-900 mb-2">Editar Abas do Cardápio</h4>
              <p className="text-xs text-rose-700 leading-relaxed mb-6">
                Organize seu site criando novas categorias ou renomeando as existentes.
              </p>

              <div className="grid gap-3">
                {sections.map(section => (
                  <div key={section.id} className="flex items-center justify-between p-4 bg-white rounded-2xl border border-rose-100 shadow-sm transition-all hover:border-rose-300">
                    <div className="flex items-center gap-3 flex-grow">
                      <div className="w-10 h-10 bg-rose-50 rounded-full flex items-center justify-center text-rose-800 font-bold flex-shrink-0">
                        {section.items.length}
