                            onKeyDown={e => e.key === 'Enter' && saveSectionName()}
                          />
                          <button onClick={saveSectionName} className="text-green-600 p-1 hover:bg-green-50 rounded-md">
                            <Check size={20} />
                          </button>
                          <button onClick={() => setEditingSectionId(null)} className="text-red-400 p-1 hover:bg-red-50 rounded-md">
                            <X size={20} />
                          </button>
                        </div>
                      ) : (
                        <div className="flex-grow">
                          <p className="font-bold text-rose-900">{section.title}</p>
                        </div>
                      )}
                    </div>

                    <div className="flex gap-1">
                      {editingSectionId !== section.id && (
                        <button 
