                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>

      {editingSweet.sweet && (
        <div className="fixed inset-0 z-[60] bg-rose-950/40 backdrop-blur-md flex items-center justify-center p-4 overflow-y-auto">
          <div className="bg-[#FFF1F2] w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in slide-in-from-bottom-8 my-auto border border-white">
