                    className="absolute inset-0 bg-rose-900/50 text-white opacity-0 group-hover:opacity-100 flex flex-col items-center justify-center transition-all duration-300 backdrop-blur-[2px]"
                  >
                    <Upload size={24} />
                    <span className="text-[10px] font-black uppercase mt-1">Upload</span>
                  </button>
                </div>
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
              </div>

              <div>
                <label className="text-[10px] font-black text-rose-400 uppercase tracking-widest ml-1 block mb-1">Nome do Produto</label>
                <input 
                  className="w-full bg-white border border-rose-100 rounded-2xl px-5 py-3 outline-none focus:ring-4 ring-rose-50 text-rose-900 font-bold transition-all shadow-sm"
                  value={editingSweet.sweet.name}
                  onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, name: e.target.value } })}
                  placeholder="Ex: Brigadeiro Belga"
                />
              </div>

              <div>
                <label className="text-[10px] font-black text-rose-400 uppercase tracking-widest ml-1 flex justify-between items-center mb-1">
                  Descrição
                  <button 
                    onClick={helpWithDescription}
                    disabled={isGenerating || !editingSweet.sweet.name}
                    className="bg-rose-50 text-rose-700 px-3 py-1 rounded-full text-[9px] font-black flex items-center gap-1 hover:bg-rose-700 hover:text-white transition-all disabled:opacity-30 border border-rose-100"
                  >
                    <Wand2 size={10} /> {isGenerating ? 'IA PENSANDO...' : 'USAR IA'}
                  </button>
                </label>
                <textarea 
                  className="w-full bg-white border border-rose-100 rounded-2xl px-5 py-4 outline-none focus:ring-4 ring-rose-50 min-h-[100px] text-rose-900 text-sm leading-relaxed transition-all shadow-sm"
                  value={editingSweet.sweet.description}
                  onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, description: e.target.value } })}
                  placeholder="Fale sobre o sabor..."
                />
              </div>

              <div>
                <label className="text-[10px] font-black text-rose-400 uppercase tracking-widest ml-1 block mb-1">Preço (R$)</label>
                <div className="relative">
                   <span className="absolute left-5 top-1/2 -translate-y-1/2 text-rose-700 font-black">R$</span>
                   <input 
                    type="number"
                    step="0.01"
                    className="w-full bg-white border border-rose-100 rounded-2xl pl-12 pr-5 py-4 outline-none focus:ring-4 ring-rose-50 text-rose-900 font-black text-xl shadow-sm"
                    value={editingSweet.sweet.price || ''}
                    onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, price: parseFloat(e.target.value) || 0 } })}
                  />
                </div>
              </div>
            </div>

            <div className="flex gap-4 mt-10">
              <button 
                onClick={() => setEditingSweet({ sectionId: '', sweet: null })} 
                className="flex-1 bg-rose-100 text-rose-500 font-black py-4 rounded-2xl hover:bg-rose-200 transition-all uppercase text-xs tracking-widest"
              >
                Descartar
              </button>
              <button 
