                className="flex-1 bg-rose-700 text-white font-black py-4 rounded-2xl hover:bg-rose-800 transition-all shadow-xl shadow-rose-100 uppercase text-xs tracking-widest"
              >
                Salvar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

