    if (!customerName.trim()) {
      alert('Por favor, informe seu nome para a comanda.');
      return;
    }

    const cleanNumber = whatsappNumber.replace(/\D/g, '');

    const header = `*❤️ DOCE PALATO - DESDE 2018 ❤️*\n_Sempre uma experiência inesquecível_\n`;
    const customer = `\n👤 *Cliente:* ${customerName}\n`;
    const items = cart.map(item => `• ${item.quantity}x ${item.name} (_R$ ${item.price.toFixed(2)} uni._)`).join('\n');
    const footer = `\n\n💰 *Total: R$ ${total.toFixed(2)}*`;
    const obs = notes.trim() ? `\n\n📝 *Observações:* ${notes}` : '';

    const message = `${header}${customer}\n*Itens:*\n${items}${obs}${footer}`;
    const encoded = encodeURIComponent(message);
    const waUrl = cleanNumber 
      ? `https://wa.me/${cleanNumber}?text=${encoded}`
      : `https://wa.me/?text=${encoded}`;

    window.open(waUrl, '_blank');

    clearCart();
    setCustomerName('');
    setNotes('');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex justify-end">
      <div 
        className="absolute inset-0 bg-rose-950/40 backdrop-blur-sm animate-in fade-in"
        onClick={onClose}
      />

      <div className="relative w-full max-w-md bg-[#FFF1F2] h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
        <div className="p-6 border-b flex items-center justify-between bg-white">
          <div>
            <h2 className="text-2xl font-bold text-rose-900">Sua Comanda</h2>
            <p className="text-xs text-rose-700 font-medium uppercase tracking-wider">Doce Palato • Strawberry & Love</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-rose-50 rounded-full text-rose-400 transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="flex-grow overflow-y-auto p-6 space-y-6">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-4">
              <div className="w-20 h-20 bg-rose-50 rounded-full flex items-center justify-center text-rose-200">
                <Trash2 size={40} />
              </div>
              <div>
                <p className="text-lg font-bold text-rose-800">Comanda vazia</p>
                <p className="text-rose-400 text-sm">Que tal um Red Velvet hoje?</p>
              </div>
            </div>
          ) : (
            <>
              <div className="space-y-4">
                {cart.map(item => (
                  <div key={item.id} className="flex gap-4 items-center p-3 rounded-2xl bg-white border border-rose-100 group shadow-sm">
                    <div className="w-14 h-14 rounded-xl overflow-hidden bg-rose-50 flex-shrink-0 border border-rose-100">
                      <img src={item.imageUrl} alt={item.name} className="w-full h-full object-cover" />
                    </div>
                    <div className="flex-grow">
                      <div className="flex justify-between items-start">
                        <h4 className="font-bold text-rose-900 text-sm leading-tight">{item.name}</h4>
                        <button onClick={() => removeFromCart(item.id)} className="text-rose-200 hover:text-red-500 transition-colors ml-2">
                          <Trash2 size={16} />
                        </button>
                      </div>
                      <div className="flex items-center justify-between mt-1">
                        <span className="text-xs font-bold text-rose-700">R$ {(item.price * item.quantity).toFixed(2)}</span>
                        <div className="flex items-center bg-rose-50 rounded-lg p-0.5 border border-rose-100">
                          <button onClick={() => updateQuantity(item.id, -1)} className="p-1 text-rose-700 hover:bg-white rounded transition-colors">
                            <Minus size={12} />
                          </button>
                          <span className="w-6 text-center text-xs font-bold text-rose-900">{item.quantity}</span>
                          <button onClick={() => updateQuantity(item.id, 1)} className="p-1 text-rose-700 hover:bg-white rounded transition-colors">
                            <Plus size={12} />
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>

              <div className="space-y-4 pt-4 border-t border-dashed border-rose-200">
                <div>
                  <label className="text-xs font-bold text-rose-400 uppercase ml-1 flex items-center gap-1 mb-1">
                    <User size={12} /> Seu Nome
                  </label>
                  <input 
                    className="w-full bg-white border border-rose-200 rounded-xl px-4 py-3 outline-none focus:ring-2 ring-rose-100 text-rose-900 transition-all"
                    placeholder="Para quem é o doce?"
                    value={customerName}
                    onChange={e => setCustomerName(e.target.value)}
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-rose-400 uppercase ml-1 flex items-center gap-1 mb-1">
                    <MessageSquare size={12} /> Observações
                  </label>
                  <textarea 
                    className="w-full bg-white border border-rose-200 rounded-xl px-4 py-3 outline-none focus:ring-2 ring-rose-100 text-rose-900 transition-all min-h-[60px]"
                    placeholder="Ex: Embalagem para presente..."
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                  />
                </div>
              </div>
            </>
          )}
        </div>

        {cart.length > 0 && (
          <div className="p-6 border-t bg-white shadow-[0_-10px_20px_-5px_rgba(0,0,0,0.05)] space-y-4">
            <div className="flex justify-between items-end">
              <div>
                <p className="text-xs text-rose-400 font-bold uppercase">Total da Experiência</p>
                <p className="text-3xl font-bold text-rose-800">R$ {total.toFixed(2)}</p>
              </div>
            </div>
            <button 
              onClick={sendToWhatsApp}
              className="w-full bg-rose-700 text-white font-bold py-4 rounded-2xl flex items-center justify-center gap-3 hover:bg-rose-800 transition-all shadow-lg shadow-rose-100 active:scale-[0.98]"
            >
              <Send size={20} />
              Enviar para o WhatsApp
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

