import React, { useState, useEffect, useMemo } from 'react';
import { ShoppingBag, Settings, LogOut, ChevronRight, Star } from 'lucide-react';
import { Section, Sweet, CartItem } from './types';
import BrigadeiroLogo from './components/BrigadeiroLogo';
import SweetCard from './components/SweetCard';
import AdminPanel from './components/AdminPanel';
import CartSheet from './components/CartSheet';
import LoginForm from './components/LoginForm';

const INITIAL_DATA: Section[] = [
  {
    id: '1',
    title: 'Clássicos da Casa',
    items: [
      { id: 'b1', name: 'Brigadeiro Belga Meio Amargo', description: 'O equilíbrio perfeito do cacau 54% com granulado premium.', price: 6.5, imageUrl: 'https://images.unsplash.com/photo-1599599810769-bcde5a160d32?auto=format&fit=crop&q=80&w=400' },
      { id: 'b2', name: 'Caramelo com Flor de Sal', description: 'Doçura intensa finalizada com cristais franceses de sal.', price: 7.5, imageUrl: 'https://images.unsplash.com/photo-1548365328-8c6db3220e4c?auto=format&fit=crop&q=80&w=400' }
    ]
  },
  {
    id: '2',
    title: 'Coleção Premium',
    items: [
      { id: 'f1', name: 'Fatia Supreme de Pistache', description: 'Camadas leves de pão de ló com creme artesanal de pistache.', price: 22.0, imageUrl: 'https://images.unsplash.com/photo-1578985545062-69928b1d9587?auto=format&fit=crop&q=80&w=400' }
    ]
  }
];

const App: React.FC = () => {
  const [sections, setSections] = useState<Section[]>(() => {
    const saved = localStorage.getItem('doce-palato-sections');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  const [whatsappNumber, setWhatsappNumber] = useState<string>(() => {
    return localStorage.getItem('doce-palato-whatsapp') || '';
  });

  const [cart, setCart] = useState<CartItem[]>([]);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [activeCategoryId, setActiveCategoryId] = useState<string>('');

  useEffect(() => {
    if (sections.length > 0 && !activeCategoryId) {
      setActiveCategoryId(sections[0].id);
    }
  }, [sections]);

  useEffect(() => {
    localStorage.setItem('doce-palato-sections', JSON.stringify(sections));
  }, [sections]);

  useEffect(() => {
    localStorage.setItem('doce-palato-whatsapp', whatsappNumber);
  }, [whatsappNumber]);

  const activeSection = useMemo(() => 
    sections.find(s => s.id === activeCategoryId), 
    [sections, activeCategoryId]
  );

  const addToCart = (sweet: Sweet) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === sweet.id);
      if (existing) {
        return prev.map(item => item.id === sweet.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...sweet, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const clearCart = () => setCart([]);

  return (
    <div className="min-h-screen pb-32 bg-[#FAFAF9]">
      {/* Header Minimalista */}
      <header className="sticky top-0 z-40 bg-white/70 backdrop-blur-2xl border-b border-stone-200/60 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => setIsAdminOpen(false)}>
          <BrigadeiroLogo size={44} />
          <div>
            <h1 className="font-logo text-2xl text-stone-900 leading-tight">Doce Palato</h1>
            <div className="flex items-center gap-1.5">
              <Star size={8} className="fill-amber-500 text-amber-500" />
              <p className="text-[9px] text-stone-500 font-bold uppercase tracking-[0.2em]">Alta Confeitaria</p>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={() => setIsAdminOpen(!isAdminOpen)}
            className={`p-2.5 rounded-2xl transition-all ${isAdminOpen ? 'bg-stone-900 text-white shadow-xl' : 'hover:bg-stone-100 text-stone-600'}`}
          >
            <Settings size={20} />
          </button>
          <button 
            onClick={() => setIsCartOpen(true)}
            className="relative group p-2.5 bg-stone-100 hover:bg-stone-900 hover:text-white rounded-2xl transition-all"
          >
            <ShoppingBag size={20} />
            {cart.length > 0 && (
              <span className="absolute -top-1.5 -right-1.5 bg-amber-600 text-white text-[10px] font-black w-5 h-5 flex items-center justify-center rounded-full border-2 border-white group-hover:border-stone-900">
                {cart.reduce((acc, item) => acc + item.quantity, 0)}
              </span>
            )}
          </button>
          {isLoggedIn && isAdminOpen && (
             <button 
              onClick={() => {setIsLoggedIn(false); setIsAdminOpen(false);}}
              className="p-2.5 hover:bg-stone-100 rounded-2xl transition-colors text-stone-400"
           >
             <LogOut size={20} />
           </button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-4xl mx-auto px-6 py-12 space-y-16">
        {isAdminOpen ? (
          isLoggedIn ? (
            <AdminPanel 
              sections={sections} 
              setSections={setSections} 
              whatsappNumber={whatsappNumber}
              setWhatsappNumber={setWhatsappNumber}
              onClose={() => setIsAdminOpen(false)} 
            />
          ) : (
            <LoginForm onLoginSuccess={() => setIsLoggedIn(true)} />
          )
        ) : (
          <div className="space-y-16">
            {/* Hero Section - Elegante */}
            <div className="relative group rounded-[3rem] overflow-hidden bg-stone-900 p-12 md:p-16 text-white shadow-2xl shadow-stone-200 border border-white/5">
              <div className="relative z-10 flex flex-col md:flex-row items-center gap-12">
                <div className="flex-1 space-y-6 text-center md:text-left">
                  <div className="inline-flex items-center gap-2 bg-white/10 px-4 py-1 rounded-full border border-white/10 text-[10px] font-bold uppercase tracking-widest text-amber-200">
                    <span className="w-1.5 h-1.5 rounded-full bg-amber-500 animate-pulse" />
                    Edição Artesanal 2024
                  </div>
                  <h2 className="text-5xl md:text-6xl font-black tracking-tight leading-[1.1]">A Arte do <br/><span className="text-amber-500 italic font-logo font-normal">Sabor Real</span></h2>
                  <p className="text-stone-400 text-lg max-w-sm font-medium leading-relaxed">
                    Descubra uma experiência sensorial única através da nossa curadoria de alta confeitaria.
                  </p>
                  <div className="pt-4 flex flex-wrap gap-3 justify-center md:justify-start">
                    {['Cacau Belga', 'Feito à Mão', 'Ingredientes Nobres'].map(tag => (
                      <span key={tag} className="px-4 py-2 bg-white/5 border border-white/10 rounded-xl text-[10px] font-black uppercase tracking-widest">{tag}</span>
                    ))}
                  </div>
                </div>
                <div className="relative transform group-hover:scale-105 duration-700 transition-all">
                  <div className="absolute inset-0 bg-amber-500/20 blur-[80px] rounded-full" />
                  <BrigadeiroLogo size={200} />
                </div>
              </div>
            </div>

            {/* Abas Minimalistas */}
            <div className="sticky top-24 z-30 py-4 bg-[#FAFAF9]/90 backdrop-blur-xl">
              <div className="flex gap-4 overflow-x-auto no-scrollbar pb-2">
                {sections.map(section => (
                  <button
                    key={section.id}
                    onClick={() => setActiveCategoryId(section.id)}
                    className={`px-8 py-3.5 rounded-2xl whitespace-nowrap text-xs font-black uppercase tracking-widest transition-all duration-500 border-2 ${
                      activeCategoryId === section.id
                      ? 'bg-stone-900 text-white border-stone-900 shadow-xl shadow-stone-900/10'
                      : 'bg-white text-stone-400 border-stone-100 hover:border-stone-200 hover:text-stone-600'
                    }`}
                  >
                    {section.title}
                  </button>
                ))}
              </div>
            </div>

            {/* Grid de Produtos */}
            <div key={activeCategoryId} className="animate-in fade-in slide-in-from-bottom-8 duration-1000">
              {activeSection ? (
                <div className="space-y-12">
                   <div className="flex items-end justify-between border-b border-stone-200 pb-6">
                    <div>
                      <h3 className="text-3xl font-black text-stone-900 tracking-tight">{activeSection.title}</h3>
                      <p className="text-xs text-stone-400 font-bold uppercase tracking-widest mt-1">Seleção Exclusiva</p>
                    </div>
                  </div>

                  {activeSection.items.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                      {activeSection.items.map(item => (
                        <SweetCard 
                          key={item.id} 
                          sweet={item} 
                          onAdd={() => addToCart(item)} 
                        />
                      ))}
                    </div>
                  ) : (
                    <div className="bg-stone-100 rounded-[3rem] p-20 text-center border-2 border-dashed border-stone-200">
                      <p className="text-stone-400 font-bold mb-1">Novidades em breve.</p>
                      <p className="text-[10px] text-stone-300 uppercase tracking-widest font-black">Nossa cozinha está criando...</p>
                    </div>
                  )}
                </div>
              ) : (
                <div className="py-20 text-center">
                  <p className="text-stone-300 font-bold italic">Selecione uma coleção.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      {/* Floating Comanda Button */}
      {cart.length > 0 && !isCartOpen && !isAdminOpen && (
        <button 
          onClick={() => setIsCartOpen(true)}
          className="fixed bottom-10 left-1/2 -translate-x-1/2 z-30 bg-stone-900 text-white shadow-2xl shadow-stone-900/20 px-12 py-6 rounded-[2.5rem] flex items-center gap-6 font-black hover:bg-amber-600 transition-all hover:scale-105 active:scale-95 border border-white/10 group"
        >
          <div className="flex items-center gap-3">
             <ShoppingBag size={20} className="group-hover:rotate-12 transition-transform" />
