import React, { useState } from 'react';
import { X, Minus, Plus, Trash2, Send, User, MessageSquare, ReceiptText } from 'lucide-react';
import { CartItem } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  whatsappNumber: string;
  updateQuantity: (id: string, delta: number) => void;
  removeFromCart: (id: string) => void;
  clearCart: () => void;
}

const CartSheet: React.FC<Props> = ({ isOpen, onClose, cart, whatsappNumber, updateQuantity, removeFromCart, clearCart }) => {
  const [customerName, setCustomerName] = useState('');
  const [notes, setNotes] = useState('');

  if (!isOpen) return null;

  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const sendToWhatsApp = () => {
    if (!customerName.trim()) {
      alert('Por favor, informe seu nome para a comanda.');
      return;
    }

    const cleanNumber = whatsappNumber.replace(/\D/g, '');
    const header = `*✨ DOCE PALATO - ALTA CONFEITARIA ✨*\n_Experiência Gourmet Artesanal_\n`;
    const customer = `\n👤 *Cliente:* ${customerName}\n`;
    const items = cart.map(item => `• ${item.quantity}x ${item.name} (_R$ ${item.price.toFixed(2)} uni._)`).join('\n');
    const footer = `\n\n💰 *Total da Experiência: R$ ${total.toFixed(2)}*`;
    const obs = notes.trim() ? `\n\n📝 *Notas:* ${notes}` : '';

    const message = `${header}${customer}\n*Seleção de Doces:*\n${items}${obs}${footer}`;
    const encoded = encodeURIComponent(message);
    const waUrl = cleanNumber 
      ? `https://wa.me/${cleanNumber}?text=${encoded}`
      : `https://wa.me/?text=${encoded}`;

    window.open(waUrl, '_blank');
    clearCart();
    setCustomerName('');
    setNotes('');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex justify-end">
      <div 
        className="absolute inset-0 bg-stone-900/40 backdrop-blur-md animate-in fade-in"
        onClick={onClose}
      />

      <div className="relative w-full max-w-md bg-[#FAFAF9] h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-500 overflow-hidden">
        {/* Topo da Comanda */}
        <div className="p-8 border-b border-stone-200 bg-white">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="bg-stone-900 text-white p-2 rounded-xl">
                 <ReceiptText size={20} />
              </div>
              <div>
                <h2 className="text-xl font-black text-stone-900 tracking-tight">Minha Comanda</h2>
                <p className="text-[10px] text-stone-400 font-black uppercase tracking-widest">Resumo da Experiência</p>
              </div>
            </div>
            <button onClick={onClose} className="p-3 hover:bg-stone-50 rounded-2xl text-stone-300 hover:text-stone-900 transition-all">
              <X size={24} />
            </button>
          </div>
        </div>

        {/* Itens */}
        <div className="flex-grow overflow-y-auto p-8 space-y-8">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-6 opacity-40">
              <div className="w-24 h-24 bg-stone-100 rounded-full flex items-center justify-center text-stone-300">
                <ShoppingBag size={48} strokeWidth={1} />
              </div>
              <div>
                <p className="text-lg font-bold text-stone-900 tracking-tight">Nenhum doce selecionado</p>
                <p className="text-stone-400 text-sm italic">O seu paladar merece um momento único.</p>
              </div>
            </div>
          ) : (
            <>
              <div className="space-y-6">
                {cart.map(item => (
                  <div key={item.id} className="flex gap-5 items-center animate-in fade-in slide-in-from-right-4">
                    <div className="w-16 h-16 rounded-2xl overflow-hidden bg-stone-100 flex-shrink-0 border border-stone-200 shadow-sm">
                      <img src={item.imageUrl} alt={item.name} className="w-full h-full object-cover" />
                    </div>
                    <div className="flex-grow">
                      <div className="flex justify-between items-start mb-1">
                        <h4 className="font-bold text-stone-900 text-sm tracking-tight">{item.name}</h4>
                        <button onClick={() => removeFromCart(item.id)} className="text-stone-300 hover:text-stone-900 transition-colors">
                          <Trash2 size={16} />
                        </button>
                      </div>
                      <div className="flex items-center justify-between">
                        <span className="text-xs font-black text-stone-900">R$ {(item.price * item.quantity).toFixed(2)}</span>
                        <div className="flex items-center bg-stone-100 rounded-xl p-1 border border-stone-200 shadow-inner">
                          <button onClick={() => updateQuantity(item.id, -1)} className="p-1.5 text-stone-500 hover:bg-white rounded-lg transition-all">
                            <Minus size={12} />
                          </button>
                          <span className="w-8 text-center text-xs font-black text-stone-900">{item.quantity}</span>
                          <button onClick={() => updateQuantity(item.id, 1)} className="p-1.5 text-stone-500 hover:bg-white rounded-lg transition-all">
                            <Plus size={12} />
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>

              {/* Formulário Elegante */}
              <div className="space-y-6 pt-8 border-t border-stone-200">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                    <User size={10} /> Titular da Comanda
                  </label>
                  <input 
                    className="w-full bg-white border border-stone-200 rounded-2xl px-6 py-4 outline-none focus:ring-4 ring-stone-100 text-stone-900 transition-all shadow-sm"
                    placeholder="Seu nome completo"
                    value={customerName}
                    onChange={e => setCustomerName(e.target.value)}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                    <MessageSquare size={10} /> Notas Adicionais
                  </label>
                  <textarea 
                    className="w-full bg-white border border-stone-200 rounded-2xl px-6 py-4 outline-none focus:ring-4 ring-stone-100 text-stone-900 transition-all min-h-[100px] shadow-sm text-sm"
                    placeholder="Ex: Embalagem para presente, restrições..."
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                  />
                </div>
              </div>
            </>
          )}
        </div>

        {/* Rodapé da Comanda */}
        {cart.length > 0 && (
          <div className="p-8 border-t bg-white shadow-[0_-15px_40px_-5px_rgba(0,0,0,0.05)] space-y-6">
            <div className="flex justify-between items-end">
              <div>
                <p className="text-[10px] text-stone-400 font-black uppercase tracking-widest mb-1">Total da Experiência</p>
                <p className="text-4xl font-black text-stone-900 tracking-tighter">
                  <span className="text-lg font-bold mr-1">R$</span>
                  {total.toFixed(2)}
                </p>
              </div>
            </div>
            <button 
              onClick={sendToWhatsApp}
              className="w-full bg-stone-900 text-white font-black py-5 rounded-[2rem] flex items-center justify-center gap-4 hover:bg-amber-600 transition-all shadow-2xl shadow-stone-900/10 active:scale-[0.98] uppercase tracking-widest text-xs"
            >
              <Send size={18} />
              Finalizar & Enviar
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default CartSheet;

import React, { useState, useRef } from 'react';
import { Plus, Trash2, Edit2, Check, X, Wand2, Upload, LayoutGrid, ListTree, ChevronRight, Phone, Coffee } from 'lucide-react';
import { Section, Sweet } from '../types';
import { GoogleGenAI } from "@google/genai";

interface Props {
  sections: Section[];
  setSections: React.Dispatch<React.SetStateAction<Section[]>>;
  whatsappNumber: string;
  setWhatsappNumber: (val: string) => void;
  onClose: () => void;
}

const AdminPanel: React.FC<Props> = ({ sections, setSections, whatsappNumber, setWhatsappNumber, onClose }) => {
  const [activeTab, setActiveTab] = useState<string>('config'); 
  const [isAddingSection, setIsAddingSection] = useState(false);
  const [newSectionTitle, setNewSectionTitle] = useState('');
  const [editingSectionId, setEditingSectionId] = useState<string | null>(null);
  const [tempSectionTitle, setTempSectionTitle] = useState('');
  const [editingSweet, setEditingSweet] = useState<{ sectionId: string, sweet: Sweet | null }>({ sectionId: '', sweet: null });
  const [isGenerating, setIsGenerating] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const addSection = () => {
    if (!newSectionTitle.trim()) return;
    const newId = Date.now().toString();
    const newSection: Section = {
      id: newId,
      title: newSectionTitle,
      items: []
    };
    setSections([...sections, newSection]);
    setNewSectionTitle('');
    setIsAddingSection(false);
    setActiveTab(newId);
  };

  const startRenaming = (section: Section) => {
    setEditingSectionId(section.id);
    setTempSectionTitle(section.title);
  };

  const saveSectionName = () => {
    if (!tempSectionTitle.trim() || !editingSectionId) return;
    setSections(prev => prev.map(s => 
      s.id === editingSectionId ? { ...s, title: tempSectionTitle } : s
    ));
    setEditingSectionId(null);
  };

  const deleteSection = (id: string) => {
    if (confirm('Tem certeza que deseja remover esta aba?')) {
      setSections(sections.filter(s => s.id !== id));
      setActiveTab('config');
    }
  };

  const startAddSweet = (sectionId: string) => {
    setEditingSweet({ 
      sectionId, 
      sweet: { id: Date.now().toString(), name: '', description: '', price: 0, imageUrl: 'https://images.unsplash.com/photo-1570476922354-81227cdbb76c?q=80&w=400&h=300&auto=format&fit=crop' } 
    });
  };

  const saveSweet = () => {
    if (!editingSweet.sweet || !editingSweet.sweet.name) return;
    setSections(prev => prev.map(s => {
      if (s.id === editingSweet.sectionId) {
        const exists = s.items.find(item => item.id === editingSweet.sweet!.id);
        if (exists) return { ...s, items: s.items.map(item => item.id === editingSweet.sweet!.id ? editingSweet.sweet! : item) };
        return { ...s, items: [...s.items, editingSweet.sweet!] };
      }
      return s;
    }));
    setEditingSweet({ sectionId: '', sweet: null });
  };

  const deleteSweet = (sectionId: string, sweetId: string) => {
    setSections(prev => prev.map(s => {
      if (sectionId === s.id) return { ...s, items: s.items.filter(item => item.id !== sweetId) };
      return s;
    }));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editingSweet.sweet) {
      const reader = new FileReader();
      reader.onloadend = () => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, imageUrl: reader.result as string } });
      reader.readAsDataURL(file);
    }
  };

  const helpWithDescription = async () => {
    if (!editingSweet.sweet?.name) return;
    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Escreva uma descrição elegante para um doce gourmet chamado "${editingSweet.sweet.name}". Máximo 15 palavras.`,
      });
      const desc = response.text || '';
      setEditingSweet(prev => prev.sweet ? ({ ...prev, sweet: { ...prev.sweet, description: desc.trim().replace(/^"|"$/g, '') } }) : prev);
    } catch (e) { console.error(e); } finally { setIsGenerating(false); }
  };

  const activeSection = sections.find(s => s.id === activeTab);

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
      <div className="flex items-center justify-between border-b border-stone-200 pb-8">
        <div>
          <h2 className="text-3xl font-black text-stone-900 tracking-tight">Atelier Admin</h2>
          <p className="text-[10px] text-stone-400 font-black uppercase tracking-[0.3em] mt-1">Gestão de Cardápio & Vendas</p>
        </div>
        <button onClick={onClose} className="p-3 hover:bg-stone-100 rounded-[1.5rem] text-stone-400 transition-all">
          <X size={28} />
        </button>
      </div>

      <nav className="flex overflow-x-auto pb-4 gap-3 no-scrollbar">
        <button 
          onClick={() => setActiveTab('config')}
          className={`flex items-center gap-2.5 px-6 py-3.5 rounded-2xl whitespace-nowrap text-xs font-black uppercase tracking-widest transition-all ${
            activeTab === 'config' ? 'bg-stone-900 text-white shadow-xl' : 'bg-white text-stone-400 border border-stone-100'
          }`}
        >
          <ListTree size={16} /> Configurações
        </button>
        {sections.map(s => (
          <button 
            key={s.id}
            onClick={() => setActiveTab(s.id)}
            className={`flex items-center gap-2.5 px-6 py-3.5 rounded-2xl whitespace-nowrap text-xs font-black uppercase tracking-widest transition-all ${
              activeTab === s.id ? 'bg-stone-900 text-white shadow-xl' : 'bg-white text-stone-400 border border-stone-100'
            }`}
          >
            <LayoutGrid size={16} /> {s.title}
          </button>
        ))}
      </nav>

      <div className="min-h-[500px]">
        {activeTab === 'config' ? (
          <div className="space-y-10 animate-in fade-in slide-in-from-left-6">
            <div className="bg-white p-8 rounded-[3rem] border border-stone-100 shadow-sm space-y-6">
              <div className="flex items-center gap-4">
                <div className="p-3 bg-amber-50 text-amber-600 rounded-2xl">
                   <Phone size={24} />
                </div>
                <div>
                  <h4 className="font-black text-stone-900 tracking-tight">Canal de Pedidos</h4>
                  <p className="text-[10px] text-stone-400 font-bold uppercase tracking-widest">Integração WhatsApp</p>
                </div>
              </div>
              <div className="space-y-3">
                <label className="text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1">Número para Recebimento</label>
                <input 
                  type="text"
                  className="w-full bg-stone-50 border border-stone-200 rounded-2xl px-6 py-4 outline-none focus:ring-4 ring-stone-100 text-stone-900 font-black text-lg transition-all"
                  placeholder="55 (DDD) 99999-9999"
                  value={whatsappNumber}
                  onChange={e => setWhatsappNumber(e.target.value)}
                />
              </div>
            </div>

            <div className="bg-stone-100/50 p-8 rounded-[3rem] border border-stone-100 space-y-8">
              <h4 className="font-black text-stone-900 tracking-tight text-xl px-2">Coleções Ativas</h4>
              <div className="grid gap-4">
                {sections.map(section => (
                  <div key={section.id} className="flex items-center justify-between p-5 bg-white rounded-[2rem] border border-stone-200 shadow-sm transition-all hover:border-amber-200 group">
                    <div className="flex items-center gap-4 flex-grow">
                      <div className="w-12 h-12 bg-stone-100 rounded-2xl flex items-center justify-center text-stone-900 font-black text-sm">
                        {section.items.length}
                      </div>
                      {editingSectionId === section.id ? (
                        <div className="flex gap-2 flex-grow mr-6">
                          <input autoFocus className="bg-stone-50 px-4 py-2 rounded-xl outline-none text-stone-900 font-bold border border-stone-200 w-full" value={tempSectionTitle} onChange={e => setTempSectionTitle(e.target.value)} onKeyDown={e => e.key === 'Enter' && saveSectionName()} />
                          <button onClick={saveSectionName} className="text-green-600 p-2 hover:bg-green-50 rounded-xl"><Check size={24} /></button>
                        </div>
                      ) : (
                        <p className="font-black text-stone-900 text-lg">{section.title}</p>
