                    <div className="flex gap-2 opacity-20 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => startRenaming(section)} className="p-2 text-stone-400 hover:text-stone-900 transition-colors"><Edit2 size={20} /></button>
                      <button onClick={() => setActiveTab(section.id)} className="p-2 text-stone-400 hover:text-stone-900 transition-colors"><ChevronRight size={24} /></button>
                      <button onClick={() => deleteSection(section.id)} className="p-2 text-stone-400 hover:text-red-500 transition-colors"><Trash2 size={20} /></button>
                    </div>
                  </div>
                ))}
              </div>
              <button onClick={() => setIsAddingSection(true)} className="w-full py-10 border-2 border-dashed border-stone-300 text-stone-400 rounded-[3rem] flex flex-col items-center justify-center gap-3 hover:bg-white hover:border-stone-400 hover:text-stone-600 transition-all group">
                <div className="p-4 bg-white rounded-2xl shadow-sm group-hover:scale-110 transition-transform"><Plus size={32} /></div>
                <span className="font-black text-[10px] uppercase tracking-[0.3em]">Nova Coleção</span>
