interface Props {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  whatsappNumber: string;
  updateQuantity: (id: string, delta: number) => void;
  removeFromCart: (id: string) => void;
  clearCart: () => void;
}

const CartSheet: React.FC<Props> = ({ isOpen, onClose, cart, whatsappNumber, updateQuantity, removeFromCart, clearCart }) => {
  const [customerName, setCustomerName] = useState('');
  const [notes, setNotes] = useState('');

  if (!isOpen) return null;

  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const sendToWhatsApp = () => {
    if (!customerName.trim()) {
      alert('Por favor, informe seu nome para a comanda.');
      return;
    }

    const cleanNumber = whatsappNumber.replace(/\D/g, '');
    const header = `*✨ DOCE PALATO - ALTA CONFEITARIA ✨*\n_Experiência Gourmet Artesanal_\n`;
    const customer = `\n👤 *Cliente:* ${customerName}\n`;
    const items = cart.map(item => `• ${item.quantity}x ${item.name} (_R$ ${item.price.toFixed(2)} uni._)`).join('\n');
    const footer = `\n\n💰 *Total da Experiência: R$ ${total.toFixed(2)}*`;
    const obs = notes.trim() ? `\n\n📝 *Notas:* ${notes}` : '';

    const message = `${header}${customer}\n*Seleção de Doces:*\n${items}${obs}${footer}`;
    const encoded = encodeURIComponent(message);
    const waUrl = cleanNumber 
      ? `https://wa.me/${cleanNumber}?text=${encoded}`
      : `https://wa.me/?text=${encoded}`;

    window.open(waUrl, '_blank');
    clearCart();
    setCustomerName('');
    setNotes('');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex justify-end">
      <div 
        className="absolute inset-0 bg-stone-900/40 backdrop-blur-md animate-in fade-in"
        onClick={onClose}
