import React, { useState } from 'react';
import { X, Minus, Plus, Trash2, Send, User, MessageSquare, MapPin, CreditCard, ShoppingBag } from 'lucide-react';
import { CartItem } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  whatsappNumber: string;
  updateQuantity: (id: string, delta: number) => void;
  removeFromCart: (id: string) => void;
  clearCart: () => void;
}

const CartSheet: React.FC<Props> = ({ isOpen, onClose, cart, whatsappNumber, updateQuantity, removeFromCart, clearCart }) => {
  const [customerName, setCustomerName] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [paymentMethod, setPaymentMethod] = useState('Pix');
  const [changeFor, setChangeFor] = useState('');
  const [notes, setNotes] = useState('');

  if (!isOpen) return null;

  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const sendToWhatsApp = () => {
    if (!customerName.trim()) {
      alert('Por favor, informe seu nome.');
      return;
    }
    if (!customerAddress.trim()) {
      alert('Por favor, informe o endereço de entrega.');
      return;
    }

    const cleanNumber = whatsappNumber.replace(/\D/g, '');

    const header = `*✨ DOCE PALATO - NOVA COMANDA ✨*\n`;
    const customerInfo = `👤 *Cliente:* ${customerName}\n📍 *Endereço:* ${customerAddress}\n`;
    const paymentInfo = `💳 *Pagamento:* ${paymentMethod}${paymentMethod === 'Dinheiro' && changeFor ? ` (Troco para R$ ${changeFor})` : ''}\n`;

    const itemsList = cart.map(item => `• ${item.quantity}x ${item.name} (R$ ${(item.price * item.quantity).toFixed(2)})`).join('\n');

    const obs = notes.trim() ? `\n📝 *Observações:* ${notes}` : '';
    const footer = `\n\n💰 *TOTAL DO PEDIDO: R$ ${total.toFixed(2)}*`;

    const message = `${header}\n${customerInfo}${paymentInfo}${obs}\n*Itens:*\n${itemsList}${footer}`;
    const encoded = encodeURIComponent(message);

    const waUrl = cleanNumber 
      ? `https://wa.me/${cleanNumber}?text=${encoded}`
      : `https://wa.me/?text=${encoded}`;

    window.open(waUrl, '_blank');
  };

  return (
    <div className="fixed inset-0 z-50 flex justify-end">
      <div 
        className="absolute inset-0 bg-stone-900/40 backdrop-blur-sm animate-in fade-in"
        onClick={onClose}
      />

      <div className="relative w-full max-w-md bg-[#FAF7F2] h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
        <div className="p-6 border-b flex items-center justify-between bg-white">
          <div>
            <h2 className="text-2xl font-bold text-stone-900">Sua Comanda</h2>
            <p className="text-xs text-stone-500 font-medium uppercase tracking-wider">Finalize seu pedido doce</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-stone-50 rounded-full text-stone-400 transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="flex-grow overflow-y-auto p-6 space-y-6">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-4">
              <div className="w-20 h-20 bg-stone-100 rounded-full flex items-center justify-center text-stone-300">
                <ShoppingBag size={40} />
              </div>
              <p className="text-lg font-bold text-stone-800">Sua comanda está vazia</p>
            </div>
          ) : (
            <>
              {/* Lista de Itens */}
              <div className="space-y-3">
                <p className="text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Itens Selecionados</p>
                {cart.map(item => (
                  <div key={item.id} className="flex gap-4 items-center p-3 rounded-2xl bg-white border border-stone-100 shadow-sm">
                    <div className="w-12 h-12 rounded-xl overflow-hidden bg-stone-50 flex-shrink-0">
                      <img src={item.imageUrl} alt={item.name} className="w-full h-full object-cover" />
                    </div>
                    <div className="flex-grow">
                      <div className="flex justify-between items-start">
                        <h4 className="font-bold text-stone-900 text-sm leading-tight">{item.name}</h4>
                        <button onClick={() => removeFromCart(item.id)} className="text-stone-300 hover:text-red-500 transition-colors">
                          <Trash2 size={14} />
                        </button>
                      </div>
                      <div className="flex items-center justify-between mt-1">
                        <span className="text-xs font-bold text-stone-700">R$ {(item.price * item.quantity).toFixed(2)}</span>
                        <div className="flex items-center bg-stone-50 rounded-lg p-0.5 border border-stone-100">
                          <button onClick={() => updateQuantity(item.id, -1)} className="p-1 text-stone-700 hover:bg-white rounded transition-colors">
                            <Minus size={10} />
                          </button>
                          <span className="w-6 text-center text-[10px] font-bold text-stone-900">{item.quantity}</span>
                          <button onClick={() => updateQuantity(item.id, 1)} className="p-1 text-stone-700 hover:bg-white rounded transition-colors">
                            <Plus size={10} />
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>

              {/* Informações de Entrega */}
              <div className="space-y-4 pt-4 border-t border-stone-200">
                <div>
                  <label className="text-xs font-bold text-stone-500 uppercase ml-1 flex items-center gap-2 mb-1">
                    <User size={14} /> Seu Nome
                  </label>
                  <input 
                    className="w-full bg-white border border-stone-200 rounded-xl px-4 py-3 outline-none focus:ring-2 ring-amber-200 text-stone-900 transition-all text-sm shadow-sm"
                    placeholder="Como podemos te chamar?"
                    value={customerName}
                    onChange={e => setCustomerName(e.target.value)}
                  />
                </div>

                <div>
                  <label className="text-xs font-bold text-stone-500 uppercase ml-1 flex items-center gap-2 mb-1">
                    <MapPin size={14} /> Endereço de Entrega
                  </label>
                  <textarea 
                    className="w-full bg-white border border-stone-200 rounded-xl px-4 py-3 outline-none focus:ring-2 ring-amber-200 text-stone-900 transition-all text-sm min-h-[80px] shadow-sm"
                    placeholder="Rua, número, bairro e referências..."
                    value={customerAddress}
                    onChange={e => setCustomerAddress(e.target.value)}
                  />
                </div>

                <div>
                  <label className="text-xs font-bold text-stone-500 uppercase ml-1 flex items-center gap-2 mb-1">
                    <CreditCard size={14} /> Forma de Pagamento
                  </label>
                  <select 
                    className="w-full bg-white border border-stone-200 rounded-xl px-4 py-3 outline-none focus:ring-2 ring-amber-200 text-stone-900 transition-all text-sm appearance-none cursor-pointer shadow-sm"
                    value={paymentMethod}
                    onChange={e => setPaymentMethod(e.target.value)}
                  >
                    <option value="Pix">Pix</option>
                    <option value="Cartão de Crédito">Cartão de Crédito</option>
                    <option value="Cartão de Débito">Cartão de Débito</option>
                    <option value="Dinheiro">Dinheiro</option>
                  </select>
                </div>

                {paymentMethod === 'Dinheiro' && (
                  <div className="animate-in fade-in slide-in-from-top-2">
                    <label className="text-xs font-bold text-stone-500 uppercase ml-1 block mb-1">Troco para quanto?</label>
                    <input 
                      type="number"
                      className="w-full bg-white border border-stone-200 rounded-xl px-4 py-3 outline-none focus:ring-2 ring-amber-200 text-stone-900 transition-all text-sm shadow-sm"
                      placeholder="Ex: 50.00 (deixe em branco se não precisar)"
                      value={changeFor}
                      onChange={e => setChangeFor(e.target.value)}
                    />
                  </div>
                )}

                <div>
                  <label className="text-xs font-bold text-stone-500 uppercase ml-1 flex items-center gap-2 mb-1">
                    <MessageSquare size={14} /> Observações Extras
                  </label>
                  <textarea 
                    className="w-full bg-white border border-stone-200 rounded-xl px-4 py-3 outline-none focus:ring-2 ring-amber-200 text-stone-900 transition-all text-sm min-h-[60px] shadow-sm"
                    placeholder="Ex: Sem açúcar, embalagem para presente..."
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                  />
                </div>
              </div>
            </>
          )}
        </div>

        {cart.length > 0 && (
          <div className="p-6 border-t bg-white shadow-[0_-10px_20px_-5px_rgba(0,0,0,0.05)] space-y-4">
            <div className="flex justify-between items-end">
              <div>
                <p className="text-xs text-stone-400 font-bold uppercase tracking-tight">Total do Pedido</p>
                <p className="text-3xl font-bold text-stone-900">R$ {total.toFixed(2)}</p>
              </div>
            </div>
            <button 
              onClick={sendToWhatsApp}
              className="w-full bg-stone-800 text-white font-bold py-4 rounded-2xl flex items-center justify-center gap-3 hover:bg-stone-900 transition-all shadow-lg active:scale-95"
            >
              <Send size={20} />
              Enviar Pedido via WhatsApp
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default CartSheet;

import React, { useState, useRef } from 'react';
import { Plus, Trash2, Edit2, Check, X, Wand2, Upload, LayoutGrid, ListTree, ChevronRight, Phone } from 'lucide-react';
import { Section, Sweet } from '../types';
import { GoogleGenAI } from "@google/genai";

interface Props {
  sections: Section[];
  setSections: React.Dispatch<React.SetStateAction<Section[]>>;
  whatsappNumber: string;
  setWhatsappNumber: (val: string) => void;
  onClose: () => void;
}

const AdminPanel: React.FC<Props> = ({ sections, setSections, whatsappNumber, setWhatsappNumber, onClose }) => {
  const [activeTab, setActiveTab] = useState<string>('config'); 
  const [isAddingSection, setIsAddingSection] = useState(false);
  const [newSectionTitle, setNewSectionTitle] = useState('');
  const [editingSectionId, setEditingSectionId] = useState<string | null>(null);
  const [tempSectionTitle, setTempSectionTitle] = useState('');
  const [editingSweet, setEditingSweet] = useState<{ sectionId: string, sweet: Sweet | null }>({ sectionId: '', sweet: null });
  const [isGenerating, setIsGenerating] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const addSection = () => {
    if (!newSectionTitle.trim()) return;
    const newId = Date.now().toString();
    const newSection: Section = {
      id: newId,
      title: newSectionTitle,
      items: []
    };
    setSections([...sections, newSection]);
    setNewSectionTitle('');
    setIsAddingSection(false);
    setActiveTab(newId);
  };

  const startRenaming = (section: Section) => {
    setEditingSectionId(section.id);
    setTempSectionTitle(section.title);
  };

  const saveSectionName = () => {
    if (!tempSectionTitle.trim() || !editingSectionId) return;
    setSections(prev => prev.map(s => 
      s.id === editingSectionId ? { ...s, title: tempSectionTitle } : s
    ));
    setEditingSectionId(null);
  };

  const deleteSection = (id: string) => {
    if (confirm('Tem certeza que deseja remover esta aba e todos os seus doces?')) {
      setSections(sections.filter(s => s.id !== id));
      setActiveTab('config');
    }
  };

  const startAddSweet = (sectionId: string) => {
    setEditingSweet({ 
      sectionId, 
      sweet: { id: Date.now().toString(), name: '', description: '', price: 0, imageUrl: 'https://images.unsplash.com/photo-1570476922354-81227cdbb76c?q=80&w=400&h=300&auto=format&fit=crop' } 
    });
  };

  const saveSweet = () => {
    if (!editingSweet.sweet || !editingSweet.sweet.name) return;

    setSections(prev => prev.map(s => {
      if (s.id === editingSweet.sectionId) {
        const exists = s.items.find(item => item.id === editingSweet.sweet!.id);
        if (exists) {
          return { ...s, items: s.items.map(item => item.id === editingSweet.sweet!.id ? editingSweet.sweet! : item) };
        }
        return { ...s, items: [...s.items, editingSweet.sweet!] };
      }
      return s;
    }));
    setEditingSweet({ sectionId: '', sweet: null });
  };

  const deleteSweet = (sectionId: string, sweetId: string) => {
    setSections(prev => prev.map(s => {
      if (sectionId === s.id) {
        return { ...s, items: s.items.filter(item => item.id !== sweetId) };
      }
      return s;
    }));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editingSweet.sweet) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditingSweet({
          ...editingSweet,
          sweet: { ...editingSweet.sweet!, imageUrl: reader.result as string }
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const helpWithDescription = async () => {
    if (!editingSweet.sweet?.name) return;
    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Escreva uma descrição curta e irresistível para um doce gourmet chamado "${editingSweet.sweet.name}". Use no máximo 15 palavras.`,
      });
      const desc = response.text || '';
      setEditingSweet(prev => prev.sweet ? ({
        ...prev,
        sweet: { ...prev.sweet, description: desc.trim().replace(/^"|"$/g, '') }
      }) : prev);
    } catch (e) {
      console.error(e);
    } finally {
      setIsGenerating(false);
    }
  };

  const activeSection = sections.find(s => s.id === activeTab);

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between border-b border-stone-200 pb-4">
        <div>
          <h2 className="text-2xl font-bold text-stone-900">Configurações</h2>
          <p className="text-xs text-stone-600 font-bold uppercase tracking-widest">Painel Administrativo</p>
        </div>
        <button onClick={onClose} className="p-2 hover:bg-stone-100 rounded-full text-stone-400 transition-colors">
          <X size={24} />
        </button>
      </div>

      <div className="flex overflow-x-auto pb-2 gap-2 no-scrollbar">
        <button 
          onClick={() => setActiveTab('config')}
          className={`flex items-center gap-2 px-4 py-2 rounded-full whitespace-nowrap text-sm font-bold transition-all border-2 ${
            activeTab === 'config' 
            ? 'bg-stone-800 text-white border-stone-800 shadow-md' 
            : 'bg-white text-stone-500 border-stone-100 hover:border-stone-200'
          }`}
        >
          <ListTree size={16} /> Geral
        </button>
        {sections.map(s => (
          <button 
            key={s.id}
            onClick={() => setActiveTab(s.id)}
            className={`flex items-center gap-2 px-4 py-2 rounded-full whitespace-nowrap text-sm font-bold transition-all border-2 ${
              activeTab === s.id 
              ? 'bg-stone-800 text-white border-stone-800 shadow-md' 
              : 'bg-white text-stone-500 border-stone-100 hover:border-stone-200'
            }`}
          >
            <LayoutGrid size={16} /> {s.title}
          </button>
        ))}
      </div>

      <div className="min-h-[400px]">
        {activeTab === 'config' ? (
          <div className="space-y-8 animate-in fade-in slide-in-from-left-4">

            <div className="bg-white p-6 rounded-[2rem] border border-stone-100 shadow-sm space-y-4">
              <div className="flex items-center gap-3 mb-2">
                <div className="p-2 bg-stone-50 text-stone-700 rounded-xl">
                   <Phone size={20} />
                </div>
                <div>
                  <h4 className="font-bold text-stone-900">WhatsApp de Pedidos</h4>
                  <p className="text-[10px] text-stone-400 font-bold uppercase tracking-widest">Destinatário das Comandas</p>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-xs font-bold text-stone-500 ml-1">Número Destino</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400 font-bold">+</span>
                  <input 
                    type="text"
                    className="w-full bg-stone-50/50 border border-stone-200 rounded-2xl pl-8 pr-4 py-4 outline-none focus:ring-4 ring-stone-100 text-stone-900 font-bold transition-all"
                    placeholder="55 (DDD) 99999-9999"
                    value={whatsappNumber}
                    onChange={e => setWhatsappNumber(e.target.value)}
                  />
                </div>
              </div>
            </div>

            <div className="bg-stone-100/30 p-6 rounded-[2rem] border border-stone-200">
              <h4 className="font-bold text-stone-900 mb-2">Editar Abas do Cardápio</h4>
              <p className="text-xs text-stone-600 leading-relaxed mb-6">
                Organize seu site criando novas categorias ou renomeando as existentes.
              </p>

              <div className="grid gap-3">
                {sections.map(section => (
                  <div key={section.id} className="flex items-center justify-between p-4 bg-white rounded-2xl border border-stone-100 shadow-sm transition-all hover:border-amber-300">
                    <div className="flex items-center gap-3 flex-grow">
                      <div className="w-10 h-10 bg-stone-100 rounded-full flex items-center justify-center text-stone-800 font-bold flex-shrink-0">
                        {section.items.length}
                      </div>

                      {editingSectionId === section.id ? (
                        <div className="flex gap-2 flex-grow mr-4">
                          <input 
                            autoFocus
                            className="bg-stone-50 px-3 py-1.5 rounded-lg outline-none text-stone-900 font-bold border border-stone-200 w-full"
                            value={tempSectionTitle}
                            onChange={e => setTempSectionTitle(e.target.value)}
                            onKeyDown={e => e.key === 'Enter' && saveSectionName()}
                          />
                          <button onClick={saveSectionName} className="text-green-600 p-1 hover:bg-green-50 rounded-md">
                            <Check size={20} />
                          </button>
                          <button onClick={() => setEditingSectionId(null)} className="text-stone-400 p-1 hover:bg-stone-50 rounded-md">
                            <X size={20} />
                          </button>
                        </div>
                      ) : (
                        <div className="flex-grow">
                          <p className="font-bold text-stone-900">{section.title}</p>
                        </div>
                      )}
                    </div>

                    <div className="flex gap-1">
                      {editingSectionId !== section.id && (
                        <button 
                          onClick={() => startRenaming(section)}
                          className="p-2 text-stone-300 hover:text-stone-800 transition-colors"
                          title="Renomear"
                        >
                          <Edit2 size={18} />
                        </button>
                      )}
                      <button 
                        onClick={() => setActiveTab(section.id)}
                        className="p-2 text-stone-300 hover:text-stone-800 transition-colors"
                        title="Ver Doces"
                      >
                        <ChevronRight size={22} />
                      </button>
                      <button 
                        onClick={() => deleteSection(section.id)}
                        className="p-2 text-stone-300 hover:text-red-500 transition-colors"
                        title="Excluir"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </div>
                ))}
              </div>

              {isAddingSection ? (
                <div className="flex gap-2 bg-white p-4 rounded-2xl border-2 border-stone-100 animate-in fade-in zoom-in-95 mt-4">
                  <input 
                    autoFocus
                    className="flex-grow bg-transparent px-2 py-2 outline-none text-stone-900 font-medium"
                    placeholder="Nome da Aba"
                    value={newSectionTitle}
                    onChange={e => setNewSectionTitle(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && addSection()}
                  />
                  <button onClick={addSection} className="bg-stone-800 text-white p-2 rounded-xl">
                    <Check size={24} />
                  </button>
                  <button onClick={() => setIsAddingSection(false)} className="bg-stone-100 text-stone-500 p-2 rounded-xl">
                    <X size={24} />
                  </button>
                </div>
              ) : (
                <button 
                  onClick={() => setIsAddingSection(true)}
                  className="w-full py-6 border-2 border-dashed border-stone-200 text-stone-400 rounded-3xl flex flex-col items-center justify-center gap-2 hover:bg-white transition-all group mt-4 shadow-sm"
                >
                  <div className="p-3 bg-white rounded-full shadow-sm group-hover:scale-110 transition-transform">
                    <Plus size={24} />
                  </div>
                  <span className="font-bold text-sm">Criar Nova Aba</span>
                </button>
              )}
            </div>
          </div>
        ) : (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <div className="flex items-center justify-between">
              <div>
                <h3 className="text-xl font-bold text-stone-900">{activeSection?.title}</h3>
                <p className="text-xs text-stone-400 font-bold uppercase tracking-wider">{activeSection?.items.length} itens cadastrados</p>
              </div>
              <button 
                onClick={() => activeSection && startAddSweet(activeSection.id)}
                className="bg-stone-800 text-white px-4 py-2 rounded-full text-xs font-bold flex items-center gap-2 hover:bg-stone-900 transition-all shadow-md active:scale-95"
              >
                <Plus size={16} /> Novo Doce Aqui
              </button>
            </div>

            <div className="grid grid-cols-1 gap-3">
              {activeSection?.items.length === 0 ? (
                <div className="py-20 text-center border-2 border-dashed border-stone-200 rounded-3xl">
                  <p className="text-stone-300 font-medium">Nenhum doce nesta aba.</p>
                </div>
              ) : (
                activeSection?.items.map(item => (
                  <div key={item.id} className="flex items-center justify-between p-3 bg-white rounded-2xl border border-stone-100 shadow-sm hover:border-amber-200 transition-colors group">
                    <div className="flex items-center gap-4">
                      <div className="w-14 h-14 rounded-xl overflow-hidden bg-stone-50 border border-stone-100">
                        <img src={item.imageUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" alt="" />
                      </div>
                      <div>
                        <p className="font-bold text-stone-900">{item.name}</p>
                        <p className="text-sm font-black text-amber-700">R$ {item.price.toFixed(2)}</p>
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <button 
                        onClick={() => activeSection && setEditingSweet({ sectionId: activeSection.id, sweet: item })} 
                        className="p-2 text-stone-300 hover:text-stone-800 transition-colors"
                        title="Editar"
                      >
                        <Edit2 size={18} />
                      </button>
                      <button 
                        onClick={() => activeSection && deleteSweet(activeSection.id, item.id)} 
                        className="p-2 text-stone-300 hover:text-red-500 transition-colors"
                        title="Remover"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>

      {editingSweet.sweet && (
        <div className="fixed inset-0 z-[60] bg-stone-900/60 backdrop-blur-md flex items-center justify-center p-4 overflow-y-auto">
          <div className="bg-[#FAF7F2] w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in slide-in-from-bottom-8 my-auto border border-white">
            <h3 className="text-2xl font-black mb-8 flex items-center gap-3 text-stone-900">
              <div className="p-2 bg-stone-800 text-white rounded-xl shadow-lg">
                <Edit2 size={24} />
              </div>
              Detalhes do Doce
            </h3>

            <div className="space-y-5">
              <div className="flex flex-col items-center gap-3">
                <div className="w-32 h-32 rounded-3xl overflow-hidden bg-white border-2 border-stone-200 relative group shadow-inner">
                  <img src={editingSweet.sweet.imageUrl} className="w-full h-full object-cover" alt="Preview" />
                  <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="absolute inset-0 bg-stone-900/50 text-white opacity-0 group-hover:opacity-100 flex flex-col items-center justify-center transition-all duration-300 backdrop-blur-[2px]"
                  >
                    <Upload size={24} />
                    <span className="text-[10px] font-black uppercase mt-1">Upload</span>
                  </button>
                </div>
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
              </div>

              <div>
                <label className="text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1 block mb-1">Nome do Produto</label>
                <input 
                  className="w-full bg-white border border-stone-200 rounded-2xl px-5 py-3 outline-none focus:ring-4 ring-amber-50 text-stone-900 font-bold transition-all shadow-sm"
                  value={editingSweet.sweet.name}
                  onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, name: e.target.value } })}
                  placeholder="Ex: Brigadeiro Belga"
                />
              </div>

              <div>
                <label className="text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1 flex justify-between items-center mb-1">
                  Descrição
                  <button 
                    onClick={helpWithDescription}
                    disabled={isGenerating || !editingSweet.sweet.name}
                    className="bg-stone-50 text-stone-700 px-3 py-1 rounded-full text-[9px] font-black flex items-center gap-1 hover:bg-stone-800 hover:text-white transition-all disabled:opacity-30 border border-stone-200"
                  >
                    <Wand2 size={10} /> {isGenerating ? 'IA PENSANDO...' : 'USAR IA'}
                  </button>
                </label>
                <textarea 
                  className="w-full bg-white border border-stone-200 rounded-2xl px-5 py-4 outline-none focus:ring-4 ring-amber-50 min-h-[100px] text-stone-900 text-sm leading-relaxed transition-all shadow-sm"
                  value={editingSweet.sweet.description}
                  onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, description: e.target.value } })}
                  placeholder="Fale sobre o sabor..."
                />
              </div>

              <div>
                <label className="text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1 block mb-1">Preço (R$)</label>
                <div className="relative">
                   <span className="absolute left-5 top-1/2 -translate-y-1/2 text-stone-700 font-black">R$</span>
                   <input 
                    type="number"
                    step="0.01"
                    className="w-full bg-white border border-stone-200 rounded-2xl pl-12 pr-5 py-4 outline-none focus:ring-4 ring-amber-50 text-stone-900 font-black text-xl shadow-sm"
                    value={editingSweet.sweet.price || ''}
                    onChange={e => setEditingSweet({ ...editingSweet, sweet: { ...editingSweet.sweet!, price: parseFloat(e.target.value) || 0 } })}
                  />
                </div>
              </div>
            </div>

            <div className="flex gap-4 mt-10">
              <button 
                onClick={() => setEditingSweet({ sectionId: '', sweet: null })} 
                className="flex-1 bg-stone-100 text-stone-500 font-black py-4 rounded-2xl hover:bg-stone-200 transition-all uppercase text-xs tracking-widest"
              >
                Descartar
              </button>
              <button 
                onClick={saveSweet} 
                className="flex-1 bg-stone-800 text-white font-black py-4 rounded-2xl hover:bg-stone-900 transition-all shadow-xl shadow-stone-100 uppercase text-xs tracking-widest"
              >
                Salvar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

