              </div>
            </div>

            <div className="flex gap-4 mt-10">
              <button 
                onClick={() => setEditingSweet({ sectionId: '', sweet: null })} 
                className="flex-1 bg-stone-100 text-stone-500 font-black py-4 rounded-2xl hover:bg-stone-200 transition-all uppercase text-xs tracking-widest"
