                    />
                  </div>
                )}

                <div>
                  <label className="text-xs font-bold text-stone-500 uppercase ml-1 flex items-center gap-2 mb-1">
                    <MessageSquare size={14} /> Observações Extras
                  </label>
                  <textarea 
                    className="w-full bg-white border border-stone-200 rounded-xl px-4 py-3 outline-none focus:ring-2 ring-amber-200 text-stone-900 transition-all text-sm min-h-[60px] shadow-sm"
                    placeholder="Ex: Sem açúcar, embalagem para presente..."
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                  />
                </div>
              </div>
            </>
          )}
        </div>

        {cart.length > 0 && (
          <div className="p-6 border-t bg-white shadow-[0_-10px_20px_-5px_rgba(0,0,0,0.05)] space-y-4">
            <div className="flex justify-between items-end">
              <div>
                <p className="text-xs text-stone-400 font-bold uppercase tracking-tight">Total do Pedido</p>
                <p className="text-3xl font-bold text-stone-900">R$ {total.toFixed(2)}</p>
              </div>
            </div>
            <button 
              onClick={sendToWhatsApp}
              className="w-full bg-stone-800 text-white font-bold py-4 rounded-2xl flex items-center justify-center gap-3 hover:bg-stone-900 transition-all shadow-lg active:scale-95"
            >
              <Send size={20} />
              Enviar Pedido via WhatsApp
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

