      { id: 'b2', name: 'Ninho com Nutella', description: 'Massa cremosa de leite ninho com coração de avelã.', price: 7.5, imageUrl: 'https://images.unsplash.com/photo-1548365328-8c6db3220e4c?auto=format&fit=crop&q=80&w=400' }
