    ]
  }
];

const App: React.FC = () => {
  const [sections, setSections] = useState<Section[]>(() => {
    const saved = localStorage.getItem('doce-palato-sections');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  const [whatsappNumber, setWhatsappNumber] = useState<string>(() => {
    return localStorage.getItem('doce-palato-whatsapp') || '';
  });

  const [cart, setCart] = useState<CartItem[]>([]);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [activeCategoryId, setActiveCategoryId] = useState<string>('');

  useEffect(() => {
    if (sections.length > 0 && !activeCategoryId) {
      setActiveCategoryId(sections[0].id);
    }
  }, [sections]);

  useEffect(() => {
    localStorage.setItem('doce-palato-sections', JSON.stringify(sections));
  }, [sections]);

  useEffect(() => {
    localStorage.setItem('doce-palato-whatsapp', whatsappNumber);
  }, [whatsappNumber]);

  const activeSection = useMemo(() => 
    sections.find(s => s.id === activeCategoryId), 
    [sections, activeCategoryId]
  );

  const addToCart = (sweet: Sweet) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === sweet.id);
      if (existing) {
        return prev.map(item => item.id === sweet.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...sweet, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const clearCart = () => setCart([]);

  const handleToggleAdmin = () => {
    setIsAdminOpen(!isAdminOpen);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setIsAdminOpen(false);
  };

  return (
    <div className="min-h-screen pb-32 selection:bg-rose-200 selection:text-rose-900 bg-[#FFF5F7]">
      {/* Header */}
      <header className="sticky top-0 z-40 bg-white/90 backdrop-blur-xl border-b border-rose-100 px-4 py-3 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => setIsAdminOpen(false)}>
          <BrigadeiroLogo size={42} />
          <div>
            <h1 className="font-logo text-xl text-emerald-800 leading-none">Doce Palato</h1>
            <p className="text-[10px] text-rose-400 font-bold uppercase tracking-tighter">Sempre uma experiência inesquecível</p>
          </div>
        </div>

        <div className="flex items-center gap-2">
          {isLoggedIn && isAdminOpen && (
             <button 
              onClick={handleLogout}
              className="p-2 hover:bg-rose-50 rounded-full transition-colors text-rose-400"
              title="Sair"
           >
             <LogOut size={22} />
           </button>
          )}
          <button 
            onClick={handleToggleAdmin}
            className={`p-2 rounded-full transition-all ${isAdminOpen ? 'bg-emerald-600 text-white shadow-inner' : 'hover:bg-rose-50 text-rose-700'}`}
            title="Gerenciar Cardápio"
          >
            <Settings size={22} />
          </button>
          <button 
            onClick={() => setIsCartOpen(true)}
            className="relative p-2 hover:bg-rose-50 rounded-full transition-all text-rose-800"
          >
            <ShoppingBag size={22} />
            {cart.length > 0 && (
              <span className="absolute -top-1 -right-1 bg-emerald-500 text-white text-[9px] font-black w-5 h-5 flex items-center justify-center rounded-full border-2 border-white animate-in zoom-in">
                {cart.reduce((acc, item) => acc + item.quantity, 0)}
              </span>
            )}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-4xl mx-auto px-4 md:px-6 py-8 space-y-12">
        {isAdminOpen ? (
          isLoggedIn ? (
            <AdminPanel 
              sections={sections} 
              setSections={setSections} 
              whatsappNumber={whatsappNumber}
              setWhatsappNumber={setWhatsappNumber}
              onClose={() => setIsAdminOpen(false)} 
            />
          ) : (
            <LoginForm onLoginSuccess={() => setIsLoggedIn(true)} />
          )
        ) : (
          <div className="space-y-10">
            {/* Banner/Hero */}
            <div className="bg-gradient-to-br from-emerald-600 via-emerald-700 to-rose-500 rounded-[3rem] p-10 text-white shadow-2xl shadow-emerald-200 flex flex-col md:flex-row items-center gap-8 overflow-hidden relative border-4 border-white/20">
              <div className="relative z-10 flex-1 text-center md:text-left">
                <div className="mb-4 inline-block bg-white/20 backdrop-blur-md px-4 py-1.5 rounded-full border border-white/30 text-[11px] font-bold uppercase tracking-widest text-white">
                  Alta Confeitaria • Premium
                </div>
                <h2 className="text-4xl md:text-5xl font-black mb-4 tracking-tight leading-tight">Um amor em cada <span className="text-rose-200 font-logo font-normal lowercase">mordida</span></h2>
                <p className="opacity-90 text-base max-w-sm mb-8 font-medium">Doces artesanais feitos com o coração e ingredientes selecionados para seu paladar.</p>
                <div className="flex flex-wrap gap-4 justify-center md:justify-start">
                  <div className="flex items-center gap-2 bg-white/10 px-4 py-2 rounded-full text-xs font-bold uppercase tracking-widest border border-white/20">
                    💖 Feito com Amor
                  </div>
                  <div className="flex items-center gap-2 bg-white/10 px-4 py-2 rounded-full text-xs font-bold uppercase tracking-widest border border-white/20">
                    👩‍🍳 Artesanal
                  </div>
                </div>
              </div>
              <div className="relative z-10 transform hover:scale-110 duration-700 transition-all drop-shadow-[0_20px_40px_rgba(0,0,0,0.3)]">
                <BrigadeiroLogo size={160} />
              </div>
              <div className="absolute -bottom-20 -left-20 w-80 h-80 bg-rose-400/20 rounded-full blur-[100px]"></div>
            </div>

            {/* Categorias */}
            <div className="sticky top-20 z-30 -mx-4 px-4 py-4 bg-[#FFF5F7]/80 backdrop-blur-md">
              <div className="flex gap-3 overflow-x-auto no-scrollbar pb-2">
                {sections.map(section => (
                  <button
                    key={section.id}
                    onClick={() => setActiveCategoryId(section.id)}
                    className={`px-6 py-3 rounded-2xl whitespace-nowrap text-sm font-bold transition-all duration-300 border-2 ${
                      activeCategoryId === section.id
                      ? 'bg-rose-500 text-white border-rose-500 shadow-lg shadow-rose-200 scale-105'
                      : 'bg-white text-emerald-700 border-rose-100 hover:border-emerald-200'
                    }`}
                  >
                    {section.title}
                  </button>
                ))}
              </div>
            </div>

            {/* Produtos */}
            <div key={activeCategoryId} className="animate-in fade-in slide-in-from-bottom-6 duration-700">
              {activeSection ? (
                <div className="space-y-8">
                   <div className="flex items-center gap-4">
                    <h3 className="text-3xl font-black text-emerald-900 tracking-tight">{activeSection.title}</h3>
                    <div className="flex-grow h-[2px] bg-gradient-to-r from-emerald-100 to-transparent"></div>
                  </div>

                  {activeSection.items.length > 0 ? (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                      {activeSection.items.map(item => (
                        <SweetCard 
                          key={item.id} 
                          sweet={item} 
                          onAdd={() => addToCart(item)} 
                        />
                      ))}
                    </div>
                  ) : (
                    <div className="bg-white rounded-[2rem] p-12 text-center border-2 border-dashed border-rose-100">
                      <p className="text-rose-300 font-bold mb-1">Nenhum item nesta aba.</p>
                      <p className="text-xs text-rose-200 uppercase tracking-widest">Em breve novas delícias!</p>
                    </div>
                  )}
                </div>
              ) : (
                <div className="py-20 text-center">
                  <p className="text-rose-300 font-bold">Selecione uma categoria.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      <CartSheet 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        cart={cart}
        whatsappNumber={whatsappNumber}
        updateQuantity={updateQuantity}
        removeFromCart={removeFromCart}
        clearCart={clearCart}
      />

      {cart.length > 0 && !isCartOpen && !isAdminOpen && (
        <button 
          onClick={() => setIsCartOpen(true)}
          className="fixed bottom-8 left-1/2 -translate-x-1/2 z-30 bg-emerald-600 text-white shadow-2xl shadow-emerald-900/20 px-10 py-5 rounded-[2rem] flex items-center gap-4 font-black hover:bg-emerald-700 transition-all hover:scale-105 active:scale-95 whitespace-nowrap border-4 border-white group"
        >
          <div className="bg-white/20 p-1.5 rounded-xl group-hover:rotate-12 transition-transform">
            <ShoppingBag size={24} />
          </div>
          <div className="text-left leading-tight">
            <span className="block text-[10px] uppercase opacity-70">Minha Comanda</span>
            <span className="text-lg">R$ {cart.reduce((acc, item) => acc + (item.price * item.quantity), 0).toFixed(2)}</span>
          </div>
          <ChevronRight size={20} className="ml-2 opacity-50" />
        </button>
      )}

      {!isAdminOpen && (
        <footer className="mt-20 py-12 px-4 text-center border-t border-rose-100 bg-white/50">
          <BrigadeiroLogo size={40} />
          <p className="text-emerald-800 text-[11px] font-bold uppercase tracking-[0.3em] mt-4 mb-2">
            Doce Palato • Gourmet
          </p>
          <p className="text-rose-300 text-[10px] font-medium italic">Sempre uma experiência inesquecível.</p>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Plus, Trash2, Edit2, Check, X, Wand2, Upload, LayoutGrid, ListTree, ChevronRight, Phone, Download, Database, RefreshCcw } from 'lucide-react';
import { Section, Sweet } from '../types';
import { GoogleGenAI } from "@google/genai";

interface Props {
  sections: Section[];
  setSections: React.Dispatch<React.SetStateAction<Section[]>>;
  whatsappNumber: string;
  setWhatsappNumber: (val: string) => void;
  onClose: () => void;
}

const AdminPanel: React.FC<Props> = ({ sections, setSections, whatsappNumber, setWhatsappNumber, onClose }) => {
  const [activeTab, setActiveTab] = useState<string>('config'); 
  const [isAddingSection, setIsAddingSection] = useState(false);
  const [newSectionTitle, setNewSectionTitle] = useState('');
  const [editingSectionId, setEditingSectionId] = useState<string | null>(null);
  const [tempSectionTitle, setTempSectionTitle] = useState('');
  const [editingSweet, setEditingSweet] = useState<{ sectionId: string, sweet: Sweet | null }>({ sectionId: '', sweet: null });
  const [isGenerating, setIsGenerating] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const importFileRef = useRef<HTMLInputElement>(null);

  const handleExportData = () => {
    const data = { sections, whatsappNumber, exportDate: new Date().toISOString() };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `doce-palato-backup-${new Date().toLocaleDateString().replace(/\//g, '-')}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImportData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (json.sections && json.whatsappNumber) {
          if (confirm('Deseja substituir o cardápio atual?')) {
            setSections(json.sections);
            setWhatsappNumber(json.whatsappNumber);
          }
        }
      } catch (err) { alert('Erro ao ler arquivo'); }
    };
    reader.readAsText(file);
  };

  const addSection = () => {
    if (!newSectionTitle.trim()) return;
    const newId = Date.now().toString();
    setSections([...sections, { id: newId, title: newSectionTitle, items: [] }]);
    setNewSectionTitle('');
    setIsAddingSection(false);
    setActiveTab(newId);
  };

  const startRenaming = (section: Section) => {
    setEditingSectionId(section.id);
    setTempSectionTitle(section.title);
  };

  const saveSectionName = () => {
    if (!tempSectionTitle.trim() || !editingSectionId) return;
    setSections(prev => prev.map(s => s.id === editingSectionId ? { ...s, title: tempSectionTitle } : s));
    setEditingSectionId(null);
  };

  const deleteSection = (id: string) => {
    if (confirm('Remover esta aba e todos os doces dentro dela?')) {
      setSections(sections.filter(s => s.id !== id));
      setActiveTab('config');
    }
  };

  const saveSweet = () => {
    if (!editingSweet.sweet || !editingSweet.sweet.name) return;
    setSections(prev => prev.map(s => {
      if (s.id === editingSweet.sectionId) {
        const exists = s.items.find(item => item.id === editingSweet.sweet!.id);
        if (exists) return { ...s, items: s.items.map(item => item.id === editingSweet.sweet!.id ? editingSweet.sweet! : item) };
        return { ...s, items: [...s.items, editingSweet.sweet!] };
      }
      return s;
    }));
    setEditingSweet({ sectionId: '', sweet: null });
  };

  const deleteSweet = (sectionId: string, sweetId: string) => {
    if (confirm('Remover este doce?')) {
      setSections(prev => prev.map(s => {
        if (s.id === sectionId) {
          return { ...s, items: s.items.filter(item => item.id !== sweetId) };
        }
        return s;
      }));
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editingSweet.sweet) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditingSweet({
          ...editingSweet,
          sweet: { ...editingSweet.sweet!, imageUrl: reader.result as string }
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const helpWithDescription = async () => {
    if (!editingSweet.sweet?.name) return;
    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Escreva uma descrição curta e irresistível para um doce gourmet chamado "${editingSweet.sweet.name}". Use no máximo 15 palavras.`,
      });
      const desc = response.text || '';
      setEditingSweet(prev => prev.sweet ? ({
        ...prev,
        sweet: { ...prev.sweet, description: desc.trim().replace(/^"|"$/g, '') }
      }) : prev);
    } catch (e) {
      console.error(e);
    } finally {
      setIsGenerating(false);
    }
  };

  const activeSection = sections.find(s => s.id === activeTab);

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex items-center justify-between border-b border-rose-100 pb-4">
        <div>
          <h2 className="text-2xl font-bold text-emerald-900">Configurações</h2>
          <p className="text-xs text-rose-400 font-bold uppercase tracking-widest">Painel Administrativo</p>
        </div>
        <button onClick={onClose} className="p-2 hover:bg-rose-50 rounded-full text-rose-300 transition-colors">
          <X size={24} />
        </button>
      </div>

      <div className="flex overflow-x-auto pb-2 gap-2 no-scrollbar">
        <button 
          onClick={() => setActiveTab('config')}
          className={`flex items-center gap-2 px-4 py-2 rounded-full whitespace-nowrap text-sm font-bold transition-all border-2 ${
            activeTab === 'config' ? 'bg-emerald-600 text-white border-emerald-600 shadow-md' : 'bg-white text-emerald-700 border-emerald-50 hover:border-rose-200'
          }`}
        >
          <ListTree size={16} /> Geral
        </button>
        {sections.map(s => (
          <button 
            key={s.id}
            onClick={() => setActiveTab(s.id)}
            className={`flex items-center gap-2 px-4 py-2 rounded-full whitespace-nowrap text-sm font-bold transition-all border-2 ${
              activeTab === s.id ? 'bg-rose-500 text-white border-rose-500 shadow-md' : 'bg-white text-rose-700 border-rose-50 hover:border-emerald-200'
            }`}
          >
            <LayoutGrid size={16} /> {s.title}
          </button>
        ))}
      </div>

      <div className="min-h-[400px]">
        {activeTab === 'config' ? (
          <div className="space-y-8 animate-in fade-in slide-in-from-left-4">

            {/* WhatsApp */}
            <div className="bg-white p-6 rounded-[2rem] border border-rose-50 shadow-sm space-y-4">
              <div className="flex items-center gap-3 mb-2">
                <div className="p-2 bg-emerald-50 text-emerald-700 rounded-xl">
                   <Phone size={20} />
                </div>
                <div>
                  <h4 className="font-bold text-emerald-900">WhatsApp de Pedidos</h4>
                  <p className="text-[10px] text-emerald-600 font-bold uppercase">Destinatário das comandas</p>
                </div>
              </div>
              <input 
                className="w-full bg-emerald-50/30 border border-emerald-100 rounded-2xl px-5 py-4 outline-none focus:ring-4 ring-rose-50 text-emerald-900 font-bold"
                placeholder="55 (DDD) 99999-9999"
                value={whatsappNumber}
                onChange={e => setWhatsappNumber(e.target.value)}
              />
            </div>

            {/* Gerenciar Abas (Categorias) */}
            <div className="bg-white p-6 rounded-[2rem] border border-emerald-50 shadow-sm space-y-4">
              <div className="flex items-center gap-3 mb-2">
                <div className="p-2 bg-rose-50 text-rose-500 rounded-xl">
                   <LayoutGrid size={20} />
                </div>
                <div>
                  <h4 className="font-bold text-emerald-900">Editar Abas do Cardápio</h4>
                  <p className="text-[10px] text-rose-400 font-bold uppercase">Gerenciar Categorias</p>
                </div>
              </div>

              <div className="grid gap-2">
                {sections.map(section => (
                  <div key={section.id} className="flex items-center justify-between p-3 bg-rose-50/30 rounded-xl border border-rose-100/50">
                    {editingSectionId === section.id ? (
                      <div className="flex gap-2 flex-grow">
                        <input 
                          autoFocus
                          className="bg-white px-3 py-1.5 rounded-lg outline-none text-emerald-900 font-bold border border-emerald-100 w-full"
                          value={tempSectionTitle}
                          onChange={e => setTempSectionTitle(e.target.value)}
                        />
                        <button onClick={saveSectionName} className="text-emerald-600"><Check size={20} /></button>
                        <button onClick={() => setEditingSectionId(null)} className="text-rose-400"><X size={20} /></button>
                      </div>
                    ) : (
                      <span className="font-bold text-emerald-800">{section.title}</span>
                    )}
                    <div className="flex gap-1">
                      <button onClick={() => startRenaming(section)} className="p-1.5 text-rose-300 hover:text-rose-600"><Edit2 size={16} /></button>
                      <button onClick={() => deleteSection(section.id)} className="p-1.5 text-rose-200 hover:text-rose-600"><Trash2 size={16} /></button>
                    </div>
                  </div>
                ))}

                {isAddingSection ? (
                  <div className="flex gap-2 p-3 bg-emerald-50 rounded-xl border border-emerald-100 animate-in zoom-in-95">
                    <input 
                      autoFocus
                      className="flex-grow bg-white px-3 py-2 rounded-lg outline-none text-emerald-900 font-bold border border-emerald-200"
                      placeholder="Nome da Aba..."
                      value={newSectionTitle}
                      onChange={e => setNewSectionTitle(e.target.value)}
                      onKeyDown={e => e.key === 'Enter' && addSection()}
                    />
                    <button onClick={addSection} className="bg-emerald-600 text-white p-2 rounded-lg"><Check size={20} /></button>
                    <button onClick={() => setIsAddingSection(false)} className="bg-rose-100 text-rose-500 p-2 rounded-lg"><X size={20} /></button>
                  </div>
                ) : (
                  <button 
                    onClick={() => setIsAddingSection(true)}
                    className="w-full py-4 border-2 border-dashed border-emerald-100 text-emerald-400 rounded-xl flex items-center justify-center gap-2 hover:bg-emerald-50 transition-all font-bold text-sm"
                  >
                    <Plus size={18} /> Criar Nova Aba
                  </button>
                )}
              </div>
            </div>

            {/* Backup */}
            <div className="bg-rose-50/50 p-6 rounded-[2rem] border border-rose-100 shadow-sm space-y-4">
              <div className="flex items-center gap-3 mb-2">
                <div className="p-2 bg-rose-500 text-white rounded-xl"><Database size={20} /></div>
                <h4 className="font-bold text-rose-900">Backup dos Dados</h4>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                <button onClick={handleExportData} className="bg-white border border-rose-200 text-rose-800 font-bold py-3 rounded-xl hover:bg-rose-100 text-sm flex items-center justify-center gap-2"><Download size={18} /> Exportar</button>
                <button onClick={() => importFileRef.current?.click()} className="bg-emerald-600 text-white font-bold py-3 rounded-xl hover:bg-emerald-700 text-sm flex items-center justify-center gap-2"><RefreshCcw size={18} /> Importar</button>
                <input type="file" ref={importFileRef} className="hidden" accept=".json" onChange={handleImportData} />
              </div>
            </div>
          </div>
        ) : (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
             <div className="flex justify-between items-center">
                <div>
                  <h3 className="text-xl font-bold text-emerald-900">{activeSection?.title}</h3>
                  <p className="text-[10px] text-rose-400 font-bold uppercase">Gerenciar itens desta categoria</p>
                </div>
                <button 
                  onClick={() => activeSection && setEditingSweet({ sectionId: activeSection.id, sweet: { id: Date.now().toString(), name: '', description: '', price: 0, imageUrl: 'https://images.unsplash.com/photo-1570476922354-81227cdbb76c?q=80&w=400' } })} 
                  className="bg-rose-500 text-white px-4 py-2 rounded-full text-xs font-bold flex items-center gap-2 hover:scale-105 transition-transform"
                >
                  <Plus size={16} /> Novo Doce
                </button>
             </div>

             <div className="grid gap-3">
                {activeSection?.items.length === 0 ? (
                  <div className="py-12 text-center border-2 border-dashed border-rose-100 rounded-3xl text-rose-200 font-bold italic">Nenhum doce aqui ainda.</div>
                ) : (
                  activeSection?.items.map(item => (
                    <div key={item.id} className="flex items-center justify-between p-3 bg-white rounded-2xl border border-rose-50 shadow-sm hover:border-emerald-200 transition-colors group">
                      <div className="flex items-center gap-4">
                        <div className="w-14 h-14 rounded-xl overflow-hidden bg-rose-50 border border-rose-100">
                          <img src={item.imageUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" alt="" />
                        </div>
                        <div>
                          <p className="font-bold text-emerald-900">{item.name}</p>
                          <p className="text-sm font-black text-rose-500">R$ {item.price.toFixed(2)}</p>
                        </div>
                      </div>
                      <div className="flex gap-1">
                        <button onClick={() => activeSection && setEditingSweet({ sectionId: activeSection.id, sweet: item })} className="p-2 text-rose-200 hover:text-emerald-700 transition-colors"><Edit2 size={18} /></button>
                        <button onClick={() => activeSection && deleteSweet(activeSection.id, item.id)} className="p-2 text-rose-200 hover:text-rose-600 transition-colors"><Trash2 size={18} /></button>
                      </div>
                    </div>
                  ))
                )}
             </div>
          </div>
        )}
      </div>

      {editingSweet.sweet && (
        <div className="fixed inset-0 z-[60] bg-emerald-950/60 backdrop-blur-md flex items-center justify-center p-4 overflow-y-auto">
          <div className="bg-[#FFF5F7] w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in slide-in-from-bottom-8 my-auto border border-white">
            <h3 className="text-2xl font-black mb-8 flex items-center gap-3 text-emerald-900">
               <div className="p-2 bg-rose-500 text-white rounded-xl shadow-lg"><Edit2 size={24} /></div>
               Detalhes do Doce
            </h3>

            <div className="space-y-4">
               <div className="flex flex-col items-center gap-2">
                 <div className="w-24 h-24 rounded-2xl overflow-hidden bg-white border-2 border-rose-100 relative group">
                   <img src={editingSweet.sweet.imageUrl} className="w-full h-full object-cover" />
                   <button onClick={() => fileInputRef.current?.click()} className="absolute inset-0 bg-emerald-900/40 text-white opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity"><Upload size={20} /></button>
                 </div>
                 <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
               </div>

               <div>
                 <label className="text-[10px] font-black text-emerald-800 uppercase ml-1 block mb-1">Nome do Produto</label>
                 <input className="w-full bg-white border border-rose-100 rounded-xl px-4 py-3 text-emerald-900 font-bold outline-none focus:ring-2 ring-rose-200" placeholder="Ex: Brigadeiro Belga" value={editingSweet.sweet.name} onChange={e => setEditingSweet({...editingSweet, sweet: {...editingSweet.sweet!, name: e.target.value}})} />
               </div>

               <div>
                <label className="text-[10px] font-black text-emerald-800 uppercase ml-1 flex justify-between items-center mb-1">
                  Descrição
                  <button onClick={helpWithDescription} disabled={isGenerating} className="text-rose-500 flex items-center gap-1 hover:underline text-[9px]"><Wand2 size={10} /> IA</button>
                </label>
                <textarea className="w-full bg-white border border-rose-100 rounded-xl px-4 py-3 text-emerald-900 text-sm outline-none focus:ring-2 ring-rose-200 min-h-[80px]" placeholder="Breve descrição..." value={editingSweet.sweet.description} onChange={e => setEditingSweet({...editingSweet, sweet: {...editingSweet.sweet!, description: e.target.value}})} />
               </div>

               <div>
                 <label className="text-[10px] font-black text-emerald-800 uppercase ml-1 block mb-1">Preço (R$)</label>
                 <input type="number" step="0.01" className="w-full bg-white border border-rose-100 rounded-xl px-4 py-3 text-emerald-900 font-black text-xl outline-none focus:ring-2 ring-rose-200" placeholder="0,00" value={editingSweet.sweet.price || ''} onChange={e => setEditingSweet({...editingSweet, sweet: {...editingSweet.sweet!, price: parseFloat(e.target.value) || 0}})} />
               </div>

               <div className="flex gap-4 mt-6">
                 <button onClick={() => setEditingSweet({sectionId: '', sweet: null})} className="flex-1 bg-rose-100 text-rose-600 font-black py-4 rounded-xl uppercase text-xs">Cancelar</button>
                 <button onClick={saveSweet} className="flex-1 bg-emerald-600 text-white font-black py-4 rounded-xl uppercase text-xs shadow-xl shadow-emerald-100">Salvar</button>
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useMemo } from 'react';
import { ShoppingBag, Settings, LogOut, ChevronRight, Sparkles } from 'lucide-react';
import { Section, Sweet, CartItem } from './types';
import BrigadeiroLogo from './components/BrigadeiroLogo';
import SweetCard from './components/SweetCard';
import AdminPanel from './components/AdminPanel';
import CartSheet from './components/CartSheet';
import LoginForm from './components/LoginForm';

const INITIAL_DATA: Section[] = [
  {
    id: '1',
